import { useState } from 'react';
import ContentCard from '../../components/ContentCard';
import { useAuth } from '../../contexts/AuthContext';
import api from '../../api';
import { toast } from 'react-hot-toast';

export default function Profile() {
    const { user, setUser } = useAuth();

    const [formData, setFormData] = useState({
        name: user?.name || '',
        email: user?.email || '',
        password: '',
        password_confirmation: '',
    });

    const [loading, setLoading] = useState(false);
    const [errors, setErrors] = useState<any>({});

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
        // Clear error when user types
        if (errors[name]) {
            setErrors((prev: any) => ({ ...prev, [name]: undefined }));
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setErrors({});

        try {
            const response = await api.put('/profile/update', formData);

            toast.success(response.data.message);

            // Update user context with new data
            if (response.data.user) {
                setUser(response.data.user);
            }

            // Reset password fields
            setFormData(prev => ({
                ...prev,
                password: '',
                password_confirmation: '',
            }));

        } catch (error: any) {
            if (error.response && error.response.data.errors) {
                setErrors(error.response.data.errors);
            } else {
                toast.error('Gagal memperbarui profil. Silakan coba lagi.');
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <ContentCard title="Pengaturan Profil">
            <form onSubmit={handleSubmit} className="space-y-6 max-w-2xl">
                <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4 mb-6">
                    <div className="flex">
                        <div className="flex-shrink-0">
                            <svg className="h-5 w-5 text-yellow-400" viewBox="0 0 20 20" fill="currentColor">
                                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                            </svg>
                        </div>
                        <div className="ml-3">
                            <p className="text-sm text-yellow-700">
                                Kosongkan field password jika tidak ingin mengubah password.
                            </p>
                        </div>
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700">
                        Nama Lengkap
                    </label>
                    <input
                        type="text"
                        name="name"
                        value={formData.name}
                        onChange={handleChange}
                        className={`mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-brand-green-main focus:ring-brand-green-main sm:text-sm
              ${errors.name ? 'border-red-500' : ''}`}
                        placeholder="Nama Lengkap"
                    />
                    {errors.name && (
                        <p className="mt-1 text-sm text-red-600">{errors.name[0]}</p>
                    )}
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700">
                        Email
                    </label>
                    <input
                        type="email"
                        name="email"
                        value={formData.email}
                        onChange={handleChange}
                        className={`mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-brand-green-main focus:ring-brand-green-main sm:text-sm
              ${errors.email ? 'border-red-500' : ''}`}
                        placeholder="alamat@email.com"
                    />
                    {errors.email && (
                        <p className="mt-1 text-sm text-red-600">{errors.email[0]}</p>
                    )}
                </div>

                <div className="border-t border-gray-200 pt-6"></div>

                <div>
                    <label className="block text-sm font-medium text-gray-700">
                        Password Baru
                    </label>
                    <input
                        type="password"
                        name="password"
                        value={formData.password}
                        onChange={handleChange}
                        className={`mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-brand-green-main focus:ring-brand-green-main sm:text-sm
              ${errors.password ? 'border-red-500' : ''}`}
                        placeholder="Minimal 6 karakter"
                    />
                    {errors.password && (
                        <p className="mt-1 text-sm text-red-600">{errors.password[0]}</p>
                    )}
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700">
                        Konfirmasi Password Baru
                    </label>
                    <input
                        type="password"
                        name="password_confirmation"
                        value={formData.password_confirmation}
                        onChange={handleChange}
                        className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-brand-green-main focus:ring-brand-green-main sm:text-sm"
                        placeholder="Ulangi password baru"
                    />
                </div>

                <div className="pt-4">
                    <button
                        type="submit"
                        disabled={loading}
                        className={`w-full flex justify-center py-2 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-brand-green-main hover:bg-brand-green-dark focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-green-main
              ${loading ? 'opacity-50 cursor-not-allowed' : ''}`}
                    >
                        {loading ? 'Menyimpan...' : 'Simpan Perubahan'}
                    </button>
                </div>
            </form>
        </ContentCard>
    );
}

import React, { useEffect, useState } from "react";
import {
    getAdminAnnouncements,
    createAnnouncement,
    deleteAnnouncement,
} from "../../../api";
import { Plus, Trash2, Megaphone } from "lucide-react";
import Modal from "../../../components/Modal";
import Swal from "sweetalert2";

interface Announcement {
    id: number;
    title: string;
    content: string;
    target_type: "all" | "guru" | "wali_murid";
    created_at: string;
    creator: {
        name: string;
    };
}

export default function AnnouncementIndex() {
    const [announcements, setAnnouncements] = useState<Announcement[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [formData, setFormData] = useState({
        title: "",
        content: "",
        target_type: "all",
    });
    const [isSubmitting, setIsSubmitting] = useState(false);

    const fetchAnnouncements = async () => {
        try {
            const response = await getAdminAnnouncements();
            setAnnouncements(response.data);
        } catch (error) {
            console.error("Failed to fetch announcements", error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchAnnouncements();
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSubmitting(true);
        try {
            await createAnnouncement(formData);
            Swal.fire("Berhasil", "Pengumuman berhasil dibuat", "success");
            setIsModalOpen(false);
            setFormData({ title: "", content: "", target_type: "all" });
            fetchAnnouncements();
        } catch (error) {
            Swal.fire("Error", "Gagal membuat pengumuman", "error");
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleDelete = async (id: number) => {
        const result = await Swal.fire({
            title: "Apakah anda yakin?",
            text: "Pengumuman akan dihapus permanen",
            icon: "warning",
            showCancelButton: true,
            confirmButtonText: "Ya, Hapus",
            cancelButtonText: "Batal",
        });

        if (result.isConfirmed) {
            try {
                await deleteAnnouncement(id);
                Swal.fire("Deleted!", "Pengumuman berhasil dihapus.", "success");
                fetchAnnouncements();
            } catch (error) {
                Swal.fire("Error", "Gagal menghapus pengumuman", "error");
            }
        }
    };

    const getTargetLabel = (type: string) => {
        switch (type) {
            case "all":
                return "Semua";
            case "guru":
                return "Guru & PTK";
            case "wali_murid":
                return "Wali Murid";
            default:
                return type;
        }
    };

    return (
        <>
            <div className="mb-6 flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-gray-800">Manajemen Pengumuman</h1>
                    <p className="text-gray-600">Buat dan kelola pengumuman untuk sekolah</p>
                </div>
                <button
                    onClick={() => setIsModalOpen(true)}
                    className="flex items-center gap-2 rounded-lg bg-indigo-600 px-4 py-2 text-white hover:bg-indigo-700"
                >
                    <Plus size={20} />
                    Buat Pengumuman
                </button>
            </div>

            <div className="grid gap-6">
                {announcements.map((announcement) => (
                    <div
                        key={announcement.id}
                        className="rounded-xl border border-gray-100 bg-white p-6 shadow-sm transition hover:shadow-md"
                    >
                        <div className="flex items-start justify-between">
                            <div className="flex items-start gap-4">
                                <div className="rounded-full bg-indigo-100 p-3 text-indigo-600">
                                    <Megaphone size={24} />
                                </div>
                                <div>
                                    <h3 className="text-lg font-semibold text-gray-900">
                                        {announcement.title}
                                    </h3>
                                    <div className="mt-1 flex items-center gap-3 text-sm text-gray-500">
                                        <span className="rounded-full bg-gray-100 px-2.5 py-0.5 text-xs font-medium text-gray-800">
                                            Ke: {getTargetLabel(announcement.target_type)}
                                        </span>
                                        <span>ÔÇó</span>
                                        <span>{new Date(announcement.created_at).toLocaleDateString("id-ID", { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</span>
                                        <span>ÔÇó</span>
                                        <span>Oleh: {announcement.creator?.name}</span>
                                    </div>
                                    <p className="mt-3 text-gray-600 whitespace-pre-wrap">{announcement.content}</p>
                                </div>
                            </div>
                            <button
                                onClick={() => handleDelete(announcement.id)}
                                className="rounded-lg p-2 text-gray-400 hover:bg-red-50 hover:text-red-600"
                                title="Hapus"
                            >
                                <Trash2 size={20} />
                            </button>
                        </div>
                    </div>
                ))}

                {announcements.length === 0 && !isLoading && (
                    <div className="text-center py-12 text-gray-500">
                        Belum ada pengumuman yang dibuat.
                    </div>
                )}
            </div>

            <Modal
                show={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title="Buat Pengumuman Baru"
            >
                <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                        <label className="mb-1 block text-sm font-medium text-gray-700">
                            Judul Pengumuman
                        </label>
                        <input
                            type="text"
                            required
                            className="w-full rounded-lg border border-gray-300 p-2.5 focus:border-indigo-500 focus:ring-indigo-500"
                            value={formData.title}
                            onChange={(e) =>
                                setFormData({ ...formData, title: e.target.value })
                            }
                            placeholder="Contoh: Libur Hari Raya"
                        />
                    </div>

                    <div>
                        <label className="mb-1 block text-sm font-medium text-gray-700">
                            Target Penerima
                        </label>
                        <select
                            className="w-full rounded-lg border border-gray-300 p-2.5 focus:border-indigo-500 focus:ring-indigo-500"
                            value={formData.target_type}
                            onChange={(e) =>
                                setFormData({ ...formData, target_type: e.target.value })
                            }
                        >
                            <option value="all">Semua (Guru, Staff & Wali Murid)</option>
                            <option value="guru">Hanya Guru & PTK</option>
                            <option value="wali_murid">Hanya Wali Murid</option>
                        </select>
                    </div>

                    <div>
                        <label className="mb-1 block text-sm font-medium text-gray-700">
                            Isi Pengumuman
                        </label>
                        <textarea
                            required
                            rows={4}
                            className="w-full rounded-lg border border-gray-300 p-2.5 focus:border-indigo-500 focus:ring-indigo-500"
                            value={formData.content}
                            onChange={(e) =>
                                setFormData({ ...formData, content: e.target.value })
                            }
                            placeholder="Tulis detail pengumuman disini..."
                        />
                    </div>

                    <div className="mt-6 flex justifying-end gap-3">
                        <button
                            type="button"
                            onClick={() => setIsModalOpen(false)}
                            className="rounded-lg border border-gray-300 bg-white px-5 py-2.5 text-sm font-medium text-gray-700 hover:bg-gray-50"
                        >
                            Batal
                        </button>
                        <button
                            type="submit"
                            disabled={isSubmitting}
                            className="rounded-lg bg-indigo-600 px-5 py-2.5 text-sm font-medium text-white hover:bg-indigo-700 disabled:opacity-50"
                        >
                            {isSubmitting ? "Mengirim..." : "Kirim Pengumuman"}
                        </button>
                    </div>
                </form>
            </Modal>
        </>
    );
}

import { useEffect, useState } from 'react';
import { Check, X, MapPin, Search, Filter, Eye, AlertCircle } from 'lucide-react';
import {
    getAdminTeacherAttendance,
    approveTeacherAttendance,
    rejectTeacherAttendance,
    getTeacherAttendanceSettings,
    updateTeacherAttendanceSettings,
} from '../../../api';

interface AttendanceRecord {
    id: number;
    user_id: number;
    user: { id: number; name: string; nip?: string };
    date: string;
    type: 'masuk' | 'keluar';
    status: 'pending' | 'approved' | 'rejected';
    photo: string | null;
    latitude: number | null;
    longitude: number | null;
    location_status: 'valid' | 'invalid';
    admin_note: string | null;
    created_at: string;
}

interface Settings {
    latitude: number;
    longitude: number;
    radius: number;
}

export default function AdminTeacherAttendance() {
    const [attendances, setAttendances] = useState<AttendanceRecord[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [filter, setFilter] = useState<{ status: string; search: string; date: string }>({
        status: 'pending',
        search: '',
        date: '',
    });
    const [selectedRecord, setSelectedRecord] = useState<AttendanceRecord | null>(null);
    const [rejectNote, setRejectNote] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

    // Settings Modal
    const [showSettings, setShowSettings] = useState(false);
    const [settings, setSettings] = useState<Settings>({ latitude: 0, longitude: 0, radius: 100 });
    const [isSavingSettings, setIsSavingSettings] = useState(false);

    useEffect(() => {
        fetchAttendances();
        fetchSettings();
    }, [filter.status, filter.date]);

    const fetchAttendances = async () => {
        setIsLoading(true);
        try {
            const response = await getAdminTeacherAttendance({
                status: filter.status || undefined,
                date: filter.date || undefined,
                search: filter.search || undefined,
            });
            setAttendances(response.data?.data || []);
        } catch (error) {
            console.error('Error fetching attendances:', error);
        } finally {
            setIsLoading(false);
        }
    };

    const fetchSettings = async () => {
        try {
            const response = await getTeacherAttendanceSettings();
            setSettings(response.data);
        } catch (error) {
            console.error('Error fetching settings:', error);
        }
    };

    const handleApprove = async (id: number) => {
        setIsSubmitting(true);
        try {
            await approveTeacherAttendance(id);
            setMessage({ type: 'success', text: 'Absensi disetujui.' });
            fetchAttendances();
            setSelectedRecord(null);
        } catch (error) {
            setMessage({ type: 'error', text: 'Gagal menyetujui absensi.' });
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleReject = async (id: number) => {
        if (!rejectNote.trim()) {
            setMessage({ type: 'error', text: 'Catatan penolakan wajib diisi.' });
            return;
        }
        setIsSubmitting(true);
        try {
            await rejectTeacherAttendance(id, rejectNote);
            setMessage({ type: 'success', text: 'Absensi ditolak.' });
            fetchAttendances();
            setSelectedRecord(null);
            setRejectNote('');
        } catch (error) {
            setMessage({ type: 'error', text: 'Gagal menolak absensi.' });
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleSaveSettings = async () => {
        setIsSavingSettings(true);
        try {
            await updateTeacherAttendanceSettings(settings);
            setMessage({ type: 'success', text: 'Pengaturan disimpan.' });
            setShowSettings(false);
        } catch (error) {
            setMessage({ type: 'error', text: 'Gagal menyimpan pengaturan.' });
        } finally {
            setIsSavingSettings(false);
        }
    };

    const getCurrentLocation = () => {
        if (navigator.geolocation) {
            navigator.geolocation.getCurrentPosition(
                (pos) => setSettings((s) => ({ ...s, latitude: pos.coords.latitude, longitude: pos.coords.longitude })),
                (err) => setMessage({ type: 'error', text: `Gagal mendapatkan lokasi: ${err.message}` })
            );
        }
    };

    const getStatusBadge = (status: string, locStatus: string) => {
        if (status === 'approved') return 'bg-green-100 text-green-800';
        if (status === 'rejected') return 'bg-red-100 text-red-800';
        if (locStatus === 'invalid') return 'bg-orange-100 text-orange-800';
        return 'bg-yellow-100 text-yellow-800';
    };

    const getStatusText = (status: string, locStatus: string) => {
        if (status === 'approved') return 'Disetujui';
        if (status === 'rejected') return 'Ditolak';
        if (locStatus === 'invalid') return 'Pending (Lokasi Invalid)';
        return 'Pending';
    };

    return (
        <div>
            <div className="flex items-center justify-between mb-6">
                <h1 className="text-2xl font-bold text-gray-800">Persetujuan Absensi Guru</h1>
                <button
                    onClick={() => setShowSettings(true)}
                    className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 flex items-center gap-2"
                >
                    <MapPin size={18} /> Pengaturan Lokasi
                </button>
            </div>

            {/* Message */}
            {message && (
                <div className={`mb-4 p-4 rounded-lg flex items-center gap-2 ${message.type === 'success' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                    {message.type === 'success' ? <Check size={20} /> : <AlertCircle size={20} />}
                    {message.text}
                    <button onClick={() => setMessage(null)} className="ml-auto text-gray-600 hover:text-gray-800">
                        <X size={16} />
                    </button>
                </div>
            )}

            {/* Filters */}
            <div className="bg-white rounded-xl shadow-sm p-4 mb-6 flex flex-wrap gap-4">
                <div className="flex items-center gap-2">
                    <Filter size={18} className="text-gray-500" />
                    <select
                        value={filter.status}
                        onChange={(e) => setFilter((f) => ({ ...f, status: e.target.value }))}
                        className="border border-gray-300 rounded-lg px-3 py-2 text-sm"
                    >
                        <option value="">Semua Status</option>
                        <option value="pending">Pending</option>
                        <option value="approved">Disetujui</option>
                        <option value="rejected">Ditolak</option>
                    </select>
                </div>
                <div>
                    <input
                        type="date"
                        value={filter.date}
                        onChange={(e) => setFilter((f) => ({ ...f, date: e.target.value }))}
                        className="border border-gray-300 rounded-lg px-3 py-2 text-sm"
                    />
                </div>
                <div className="flex items-center gap-2 flex-1">
                    <Search size={18} className="text-gray-500" />
                    <input
                        type="text"
                        placeholder="Cari nama guru..."
                        value={filter.search}
                        onChange={(e) => setFilter((f) => ({ ...f, search: e.target.value }))}
                        onKeyDown={(e) => e.key === 'Enter' && fetchAttendances()}
                        className="border border-gray-300 rounded-lg px-3 py-2 text-sm flex-1"
                    />
                </div>
            </div>

            {/* Table */}
            {isLoading ? (
                <div className="flex justify-center py-12">
                    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
                </div>
            ) : attendances.length === 0 ? (
                <div className="bg-white rounded-xl shadow-sm p-12 text-center">
                    <p className="text-gray-500">Tidak ada data absensi.</p>
                </div>
            ) : (
                <div className="bg-white rounded-xl shadow-sm overflow-hidden">
                    <table className="w-full">
                        <thead className="bg-gray-50">
                            <tr>
                                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Guru</th>
                                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Tanggal</th>
                                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Jenis</th>
                                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Lokasi</th>
                                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
                                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">Aksi</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-200">
                            {attendances.map((record) => (
                                <tr key={record.id} className={`hover:bg-gray-50 ${record.location_status === 'invalid' ? 'bg-red-50' : ''}`}>
                                    <td className="px-4 py-4">
