                                >
                                    {isSavingSettings ? <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div> : <Check size={18} />}
                                    Simpan
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useEffect, useState, useMemo } from 'react';
import { getStudentAttendance, storeStudentAttendance, getClassRooms } from '../../../api';
import type { StudentAttendance as StudentAttendanceType, ClassRoom, Student } from '../../../types';

interface AttendanceData {
  students: Student[];
  attendances: StudentAttendanceType[];
}

export default function StudentAttendance() {
  const [classRooms, setClassRooms] = useState<ClassRoom[]>([]);
  const [grades, setGrades] = useState<string[]>([]); // Added state for grades

  const [filters, setFilters] = useState({
    date: new Date().toISOString().split('T')[0],
    grade: '',
    class_room_id: '',
  });

  const [data, setData] = useState<AttendanceData | null>(null);
  const [isLoading, setIsLoading] = useState(false); // Changed default to false, will load when fetching
  const [isSaving, setIsSaving] = useState(false);
  const [attendanceInput, setAttendanceInput] = useState<Record<number, string>>({});

  useEffect(() => {
    fetchClassRooms();
  }, []);

  useEffect(() => {
    fetchAttendance();
  }, [filters]); // Trigger on any filter change

  const fetchClassRooms = async () => {
    try {
      const response = await getClassRooms();
      setClassRooms(response.data);
    } catch (error) {
      console.error('Error fetching class rooms:', error);
    }
  };

  // Removed derived grades since we get them from API now, but we need to keep filteredClassRooms
  // Filter rombel based on selected grade
  const filteredClassRooms = useMemo(() => {
    if (!filters.grade) return classRooms;
    return classRooms.filter(cr => String(cr.grade) === filters.grade);
  }, [filters.grade, classRooms]);

  // Handle Grade Change
  const handleGradeChange = (grade: string) => {
    setFilters(prev => ({ ...prev, grade, class_room_id: '' }));
  };

  const fetchAttendance = async () => {
    setIsLoading(true);
    try {
      const response = await getStudentAttendance({
        date: filters.date,
        class_room_id: filters.class_room_id ? Number(filters.class_room_id) : undefined,
        grade: filters.grade || undefined, // Send grade if selected
      });
      setData(response.data);
      if (response.data.grades) {
        setGrades(response.data.grades);
      }

      // Initialize attendance input from existing data
      const initial: Record<number, string> = {};
      response.data.students?.forEach((student: Student) => {
        const existing = response.data.attendances?.find(
          (a: StudentAttendanceType) => a.student_id === student.id
        );
        initial[student.id] = existing?.status || 'hadir';
      });
      setAttendanceInput(initial);
    } catch (error) {
      console.error('Error fetching attendance:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSave = async () => {
    setIsSaving(true);
    try {
      const attendances = Object.entries(attendanceInput).map(([student_id, status]) => ({
        student_id: Number(student_id),
        date: filters.date,
        status,
      }));
      await storeStudentAttendance(attendances);
      alert('Absensi berhasil disimpan!');
      fetchAttendance(); // Refresh data after save
    } catch (error) {
      console.error('Error saving attendance:', error);
      alert('Gagal menyimpan absensi');
    } finally {
      setIsSaving(false);
    }
  };

  const statusOptions = [
    { value: 'hadir', label: 'Hadir', color: 'bg-green-100 text-green-800' },
    { value: 'izin', label: 'Izin', color: 'bg-yellow-100 text-yellow-800' },
    { value: 'sakit', label: 'Sakit', color: 'bg-blue-100 text-blue-800' },
    { value: 'alpha', label: 'Alpha', color: 'bg-red-100 text-red-800' },
  ];

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold text-gray-800">Absensi Siswa</h1>
      </div>

      {/* Filters */}
      <div className="bg-white rounded-xl shadow-sm p-4 mb-6">
        <div className="flex flex-wrap gap-4 items-end">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Tanggal</label>
            <input
              type="date"
              value={filters.date}
              onChange={(e) => setFilters(prev => ({ ...prev, date: e.target.value }))}
              className="border border-gray-300 rounded-lg px-3 py-2 text-sm"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Kelas</label>
            <select
              value={filters.grade}
              onChange={(e) => handleGradeChange(e.target.value)}
              className="border border-gray-300 rounded-lg px-3 py-2 text-sm min-w-[80px]"
            >
              <option value="">Semua</option>
              {grades.map(g => (
                <option key={g} value={g}>{g}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Rombel</label>
            <select
              value={filters.class_room_id}
              onChange={(e) => setFilters(prev => ({ ...prev, class_room_id: e.target.value }))}
              className="border border-gray-300 rounded-lg px-3 py-2 text-sm min-w-[80px]"
            >
              <option value="">Semua</option>
              {filteredClassRooms.map((room) => (
                <option key={room.id} value={room.id}>{room.name}</option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-green-main"></div>
        </div>
      ) : !data?.students?.length ? (
        <div className="bg-white rounded-xl shadow-sm p-12 text-center">
          <p className="text-gray-500">Tidak ada siswa ditemukan.</p>
        </div>
      ) : (
        <>
          <div className="bg-white rounded-xl shadow-sm overflow-hidden mb-4">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      No
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Nama
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Status
                    </th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200">
                  {data.students.map((student, index) => (
                    <tr key={student.id} className="hover:bg-gray-50">
                      <td className="px-6 py-4 text-sm text-gray-600">{index + 1}</td>
                      <td className="px-6 py-4 font-medium text-gray-800">{student.name}</td>
                      <td className="px-6 py-4">
                        <div className="flex gap-1">
                          {statusOptions.map((option) => (
                            <button
                              key={option.value}
                              onClick={() => setAttendanceInput(prev => ({ ...prev, [student.id]: option.value }))}
                              className={`px-2 py-1 text-xs rounded-full transition ${attendanceInput[student.id] === option.value
                                ? option.color
                                : 'bg-gray-100 text-gray-500 hover:bg-gray-200'
                                }`}
                            >
                              {option.label}
                            </button>
                          ))}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="flex justify-end">
            <button
              onClick={handleSave}
              disabled={isSaving}
              className="bg-brand-green-main text-white px-6 py-2 rounded-lg hover:bg-brand-green-dark transition disabled:opacity-50"
            >
              {isSaving ? 'Menyimpan...' : 'Simpan Absensi'}
            </button>
          </div>
        </>
      )}
    </div>
  );
}

import { useEffect, useState, useMemo } from 'react';
import { getStudentAttendanceReport, getStudentAttendanceExportUrl } from '../../../api';
import type { StudentAttendanceReportItem, ClassRoom } from '../../../types';

interface ReportFilters {
    start_date: string;
    end_date: string;
    grade: string;
    class_room_id: string;
}

export default function StudentAttendanceReport() {
    const [students, setStudents] = useState<StudentAttendanceReportItem[]>([]);
    const [grades, setGrades] = useState<string[]>([]);
    const [classRooms, setClassRooms] = useState<ClassRoom[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    const [filters, setFilters] = useState<ReportFilters>({
        start_date: new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0],
        end_date: new Date().toISOString().split('T')[0],
        grade: '',
        class_room_id: '',
    });

    useEffect(() => {
        fetchReport();
    }, [filters]);

    const fetchReport = async () => {
        setIsLoading(true);
        try {
            const response = await getStudentAttendanceReport({
                start_date: filters.start_date,
                end_date: filters.end_date,
                grade: filters.grade || undefined,
                class_room_id: filters.class_room_id ? Number(filters.class_room_id) : undefined,
            });
            setStudents(response.data.students);
            setGrades(response.data.grades);
            setClassRooms(response.data.classRooms);
        } catch (error) {
            console.error('Error fetching report:', error);
        } finally {
            setIsLoading(false);
        }
    };

    const filteredClassRooms = useMemo(() => {
        if (!filters.grade) return classRooms;
        return classRooms.filter(cr => cr.grade?.toString() === filters.grade);
    }, [filters.grade, classRooms]);

