                                            </td>
                                            <td className="px-6 py-4">
                                                <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-800">
                                                    {student.alpha_count}
                                                </span>
                                            </td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr>
                                        <td colSpan={8} className="px-6 py-12 text-center text-gray-500">
                                            Belum ada data siswa.
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useEffect, useState } from 'react';
import { getAttendance } from '../../../api';
import type { Attendance } from '../../../types';

export default function TeacherAttendance() {
  const [attendances, setAttendances] = useState<Attendance[]>([]);
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    fetchAttendance();
  }, [selectedDate]);

  const fetchAttendance = async () => {
    setIsLoading(true);
    try {
      const response = await getAttendance(selectedDate);
      // Handle response that might be array directly or nested in data property
      const data = response.data;
      setAttendances(Array.isArray(data) ? data : (data?.data || []));
    } catch (error) {
      console.error('Error fetching attendance:', error);
      setAttendances([]);
    } finally {
      setIsLoading(false);
    }
  };

  const getStatusBadge = (status: string) => {
    const colors: Record<string, string> = {
      hadir: 'bg-green-100 text-green-800',
      izin: 'bg-yellow-100 text-yellow-800',
      sakit: 'bg-blue-100 text-blue-800',
      alpha: 'bg-red-100 text-red-800',
    };
    return colors[status] || 'bg-gray-100 text-gray-800';
  };

  // Summary stats
  const stats = {
    hadir: attendances.filter(a => a.status === 'hadir').length,
    izin: attendances.filter(a => a.status === 'izin').length,
    sakit: attendances.filter(a => a.status === 'sakit').length,
    alpha: attendances.filter(a => a.status === 'alpha').length,
  };

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold text-gray-800">Absensi Guru/PTK</h1>
      </div>

      {/* Date Filter */}
      <div className="bg-white rounded-xl shadow-sm p-4 mb-6">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Tanggal</label>
          <input
            type="date"
            value={selectedDate}
            onChange={(e) => setSelectedDate(e.target.value)}
            className="border border-gray-300 rounded-lg px-3 py-2 text-sm"
          />
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
        <div className="bg-white rounded-xl shadow-sm p-4">
          <p className="text-sm text-gray-500">Hadir</p>
          <p className="text-2xl font-bold text-green-600">{stats.hadir}</p>
        </div>
        <div className="bg-white rounded-xl shadow-sm p-4">
          <p className="text-sm text-gray-500">Izin</p>
          <p className="text-2xl font-bold text-yellow-600">{stats.izin}</p>
        </div>
        <div className="bg-white rounded-xl shadow-sm p-4">
          <p className="text-sm text-gray-500">Sakit</p>
          <p className="text-2xl font-bold text-blue-600">{stats.sakit}</p>
        </div>
        <div className="bg-white rounded-xl shadow-sm p-4">
          <p className="text-sm text-gray-500">Alpha</p>
          <p className="text-2xl font-bold text-red-600">{stats.alpha}</p>
        </div>
      </div>

      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-green-main"></div>
        </div>
      ) : attendances.length === 0 ? (
        <div className="bg-white rounded-xl shadow-sm p-12 text-center">
          <p className="text-gray-500">Tidak ada data absensi untuk tanggal ini.</p>
        </div>
      ) : (
        <div className="bg-white rounded-xl shadow-sm overflow-hidden">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  No
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Nama
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Waktu
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Status
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {attendances.map((attendance, index) => (
                <tr key={attendance.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 text-sm text-gray-600">{index + 1}</td>
                  <td className="px-6 py-4 font-medium text-gray-800">{attendance.teacher?.name || '-'}</td>
                  <td className="px-6 py-4 text-sm text-gray-600">{attendance.time || '-'}</td>
                  <td className="px-6 py-4">
                    <span className={`text-xs px-2 py-1 rounded-full capitalize ${getStatusBadge(attendance.status)}`}>
                      {attendance.status}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { getClassRooms, getClassDaySlots, updateClassDaySlots } from '../../../api';
import { Clock, Save, AlertCircle } from 'lucide-react';
import type { ClassRoom, ClassDaySlot } from '../../../types';

type Day = 'senin' | 'selasa' | 'rabu' | 'kamis' | 'minggu' | 'sabtu';

const DAYS: { key: string; label: string }[] = [
    { key: 'sabtu', label: 'Sabtu' },
    { key: 'minggu', label: 'Ahad' },
    { key: 'senin', label: 'Senin' },
    { key: 'selasa', label: 'Selasa' },
    { key: 'rabu', label: 'Rabu' },
    { key: 'kamis', label: 'Kamis' },
];

const DEFAULT_SLOTS = 8;

export default function ClassDaySlotsIndex() {
    const [classRooms, setClassRooms] = useState<ClassRoom[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [selectedClass, setSelectedClass] = useState<number | null>(null);
    const [slots, setSlots] = useState<Record<Day, number>>({
        senin: DEFAULT_SLOTS,
        selasa: DEFAULT_SLOTS,
        rabu: DEFAULT_SLOTS,
        kamis: DEFAULT_SLOTS,
        sabtu: DEFAULT_SLOTS,
        minggu: DEFAULT_SLOTS,
    });
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    useEffect(() => {
        fetchClassRooms();
    }, []);

    useEffect(() => {
        if (selectedClass) {
            fetchSlots();
        }
    }, [selectedClass]);

    const fetchClassRooms = async () => {
        try {
            const res = await getClassRooms();
            setClassRooms(res.data);
            if (res.data.length > 0) {
                setSelectedClass(res.data[0].id);
            }
        } catch (err) {
            console.error('Error fetching classrooms:', err);
        } finally {
            setLoading(false);
        }
    };

    const fetchSlots = async () => {
        if (!selectedClass) return;
        try {
            const res = await getClassDaySlots(selectedClass);

            // Initialize local slots from fetched data
            const newSlots: Record<Day, number> = {
                senin: DEFAULT_SLOTS,
                selasa: DEFAULT_SLOTS,
                rabu: DEFAULT_SLOTS,
                kamis: DEFAULT_SLOTS,
                sabtu: DEFAULT_SLOTS,
                minggu: DEFAULT_SLOTS,
            };
            res.data.forEach((slot: ClassDaySlot) => {
                if (newSlots[slot.day as Day] !== undefined) {
                    newSlots[slot.day as Day] = slot.total_slots;
                }
            });
            setSlots(newSlots);
        } catch (err) {
            console.error('Error fetching slots:', err);
        }
    };

    const handleSlotChange = (day: Day, value: number) => {
        setSlots(prev => ({
            ...prev,
            [day]: Math.max(1, Math.min(12, value))
        }));
    };

    const handleSave = async () => {
        if (!selectedClass) return;

        setSaving(true);
        setError('');
        setSuccess('');

        try {
            const slotsData = DAYS.map(day => ({
                day: day.key,
                total_slots: slots[day.key as Day]
            }));

            await updateClassDaySlots(selectedClass, slotsData);
            setSuccess('Konfigurasi slot berhasil disimpan!');
            fetchSlots();
        } catch (err: unknown) {
            const error = err as { response?: { data?: { error?: string } } };
            setError(error.response?.data?.error || 'Gagal menyimpan konfigurasi');
        } finally {
            setSaving(false);
        }
    };

    const selectedClassData = classRooms.find(c => c.id === selectedClass);

    if (loading) {
        return (
            <div className="flex items-center justify-center h-64">
                <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-emerald-500"></div>
            </div>
        );
    }

    return (
        <div className="p-6">
            <div className="flex justify-between items-center mb-6">
                <h1 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
                    <Clock className="text-emerald-600" />
                    Konfigurasi Jam Pelajaran
                </h1>
            </div>

            {error && (
                <div className="mb-4 p-4 bg-red-100 text-red-700 rounded-lg flex items-center gap-2">
                    <AlertCircle size={20} />
                    {error}
                </div>
            )}

            {success && (
                <div className="mb-4 p-4 bg-green-100 text-green-700 rounded-lg">
                    {success}
                </div>
            )}

            {/* Class Selector */}
            <div className="bg-white rounded-xl shadow-sm p-4 mb-6">
                <div className="flex items-center gap-4">
                    <label className="font-medium text-gray-700">Pilih Kelas:</label>
                    <select
                        value={selectedClass || ''}
                        onChange={(e) => setSelectedClass(Number(e.target.value))}
                        className="px-4 py-2 border rounded-lg focus:ring-2 focus:ring-emerald-500"
                    >
                        {classRooms.map(c => (
                            <option key={c.id} value={c.id}>
                                Kelas {c.grade} {c.name}
                            </option>
                        ))}
                    </select>
                </div>
            </div>

            {/* Slots Configuration */}
            <div className="bg-white rounded-xl shadow-sm p-6">
                <h2 className="text-lg font-semibold text-gray-800 mb-4">
                    Jumlah Jam Pelajaran per Hari - Kelas {selectedClassData?.grade} {selectedClassData?.name}
                </h2>

                <p className="text-gray-600 text-sm mb-6">
                    Tentukan berapa jam pelajaran (slot) yang akan diadakan untuk setiap hari dalam seminggu.
                    Nilai minimum 1 jam dan maksimum 12 jam.
                </p>

                <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-4 mb-6">
                    {DAYS.map(day => (
                        <div key={day.key} className="bg-gray-50 rounded-lg p-4 border border-gray-200">
                            <label className="block font-medium text-gray-700 mb-2">
                                {day.label}
                            </label>
                            <div className="flex items-center gap-2">
                                <button
                                    onClick={() => handleSlotChange(day.key as Day, slots[day.key as Day] - 1)}
                                    className="w-10 h-10 bg-gray-200 rounded-lg hover:bg-gray-300 transition-colors flex items-center justify-center font-bold text-lg"
                                >
                                    -
                                </button>
                                <input
                                    type="number"
                                    value={slots[day.key as Day]}
                                    onChange={(e) => handleSlotChange(day.key as Day, parseInt(e.target.value) || 1)}
                                    className="w-20 text-center px-3 py-2 border rounded-lg focus:ring-2 focus:ring-emerald-500"
                                    min={1}
                                    max={12}
                                />
                                <button
                                    onClick={() => handleSlotChange(day.key as Day, slots[day.key as Day] + 1)}
                                    className="w-10 h-10 bg-gray-200 rounded-lg hover:bg-gray-300 transition-colors flex items-center justify-center font-bold text-lg"
                                >
                                    +
                                </button>
                                <span className="text-gray-500 text-sm ml-2">jam</span>
                            </div>
                        </div>
                    ))}
                </div>

                <div className="flex justify-end">
                    <button
                        onClick={handleSave}
                        disabled={saving}
                        className="flex items-center gap-2 px-6 py-3 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-colors disabled:opacity-50"
                    >
                        <Save size={18} />
                        {saving ? 'Menyimpan...' : 'Simpan Konfigurasi'}
                    </button>
                </div>
            </div>

            {/* Info Box */}
            <div className="mt-6 p-4 bg-blue-50 border border-blue-200 rounded-lg text-sm text-blue-800">
                <strong>Catatan:</strong> Konfigurasi ini akan digunakan saat generate jadwal otomatis.
                Pastikan jumlah jam sesuai dengan kurikulum dan kapasitas guru yang tersedia.
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import {
    getClassRooms,
    getClassSubjects,
    storeClassSubject,
    deleteClassSubject,
    getSubjects,
    getTeachers
} from '../../../api';
import { Trash2, Plus, Save, Pencil } from 'lucide-react';
import type { ClassRoom, Subject, Teacher } from '../../../types';

interface ClassSubject {
    id: number;
    class_room_id: number;
    subject_id: number;
    weekly_hours: number;
    teacher_id?: number;
    subject: Subject;
    teacher?: Teacher;
}

export default function CurriculumIndex() {
    // State for data
    const [classRooms, setClassRooms] = useState<ClassRoom[]>([]);
    const [subjects, setSubjects] = useState<Subject[]>([]);
    const [teachers, setTeachers] = useState<Teacher[]>([]);

    // State for selection
    const [selectedClassId, setSelectedClassId] = useState<number | ''>('');
    const [classSubjects, setClassSubjects] = useState<ClassSubject[]>([]);

    // State for form
    const [form, setForm] = useState({
        subject_id: '',
        teacher_id: '',
        weekly_hours: 2
    });

    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    useEffect(() => {
        fetchInitialData();
    }, []);

    useEffect(() => {
        if (selectedClassId) {
            fetchClassSubjects(Number(selectedClassId));
        } else {
            setClassSubjects([]);
        }
    }, [selectedClassId]);

    const fetchInitialData = async () => {
        try {
            const [classesRes, subjectsRes, teachersRes] = await Promise.all([
                getClassRooms(),
                getSubjects(),
                getTeachers()
            ]);
            setClassRooms(Array.isArray(classesRes.data) ? classesRes.data : []);
            setSubjects(Array.isArray(subjectsRes.data) ? subjectsRes.data : []);
            setTeachers(Array.isArray(teachersRes.data?.teachers) ? teachersRes.data.teachers : (Array.isArray(teachersRes.data) ? teachersRes.data : []));
        } catch (err) {
            console.error('Error fetching initial data:', err);
            setError('Gagal memuat data awal');
        }
    };

    const fetchClassSubjects = async (classId: number) => {
        setLoading(true);
        try {
            const res = await getClassSubjects(classId);
            setClassSubjects(Array.isArray(res.data) ? res.data : []);
        } catch (err) {
            console.error('Error fetching class subjects:', err);
            setError('Gagal memuat data mapel kelas');
        } finally {
            setLoading(false);
        }
    };

    // State for edit
    const [editingItem, setEditingItem] = useState<ClassSubject | null>(null);

    const handleEdit = (item: ClassSubject) => {
        setEditingItem(item);
        setForm({
            subject_id: String(item.subject_id),
            teacher_id: item.teacher_id ? String(item.teacher_id) : '',
            weekly_hours: item.weekly_hours
        });
        setError('');
        setSuccess('');
    };

    const handleCancelEdit = () => {
        setEditingItem(null);
        setForm({
            subject_id: '',
            teacher_id: '',
            weekly_hours: 2
        });
        setError('');
        setSuccess('');
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        setSuccess('');

        if (!selectedClassId) {
            setError('Pilih kelas terlebih dahulu');
            return;
        }

        try {
            await storeClassSubject({
                class_room_id: Number(selectedClassId),
                subject_id: Number(form.subject_id),
                teacher_id: form.teacher_id ? Number(form.teacher_id) : undefined,
                weekly_hours: Number(form.weekly_hours)
            });

            setSuccess(editingItem ? 'Alokasi berhasil diperbarui' : 'Mata pelajaran berhasil dialokasikan');
            fetchClassSubjects(Number(selectedClassId));

            // Reset form
            handleCancelEdit();
        } catch (err: any) {
            setError(err.response?.data?.message || 'Gagal menyimpan data');
        }
    };

    const handleDelete = async (id: number) => {
        if (!confirm('Yakin ingin menghapus mapel ini dari kelas?')) return;

        try {
            await deleteClassSubject(id);
            if (editingItem?.id === id) handleCancelEdit();
            if (selectedClassId) fetchClassSubjects(Number(selectedClassId));
        } catch (err) {
            console.error('Error deleting:', err);
            setError('Gagal menghapus data');
        }
    };

    // Calculate total hours
    const totalHours = classSubjects.reduce((sum, item) => sum + item.weekly_hours, 0);

    return (
        <div className="p-6 space-y-6">
            <h1 className="text-2xl font-bold text-gray-800">Alokasi Kurikulum Per Kelas</h1>

            {/* Class Selector */}
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
                <label className="block text-sm font-medium text-gray-700 mb-2">Pilih Kelas</label>
                <select
                    value={selectedClassId}
                    onChange={(e) => {
                        setSelectedClassId(e.target.value ? Number(e.target.value) : '');
                        handleCancelEdit();
                    }}
                    className="w-full md:w-1/3 px-3 py-2 border rounded-lg focus:ring-2 focus:ring-emerald-500"
                >
                    <option value="">-- Pilih Kelas --</option>
                    {classRooms.map((cr) => (
                        <option key={cr.id} value={cr.id}>{cr.name} (Kelas {cr.grade})</option>
                    ))}
                </select>
            </div>

            {selectedClassId && (
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Form Section */}
                    <div className="lg:col-span-1">
                        <div className={`bg-white p-6 rounded-xl shadow-sm border ${editingItem ? 'border-amber-200 ring-2 ring-amber-100' : 'border-gray-100'} sticky top-6 transition-all`}>
                            <h2 className={`text-lg font-bold ${editingItem ? 'text-amber-700' : 'text-gray-800'} mb-4 flex items-center gap-2`}>
                                {editingItem ? (
                                    <>
                                        <Pencil size={20} /> Edit Alokasi
                                    </>
                                ) : (
                                    <>
                                        <Plus size={20} className="text-emerald-600" /> Tambah Mapel
                                    </>
                                )}
                            </h2>

                            {error && <div className="mb-4 p-3 bg-red-50 text-red-700 rounded-lg text-sm">{error}</div>}
                            {success && <div className="mb-4 p-3 bg-green-50 text-green-700 rounded-lg text-sm">{success}</div>}

                            <form onSubmit={handleSubmit} className="space-y-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Mata Pelajaran</label>
                                    <select
                                        value={form.subject_id}
                                        onChange={(e) => setForm({ ...form, subject_id: e.target.value })}
                                        className={`w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-emerald-500 ${editingItem ? 'bg-gray-100 cursor-not-allowed' : ''}`}
                                        required
                                        disabled={!!editingItem}
                                    >
                                        <option value="">-- Pilih Mapel --</option>
                                        {subjects.map((s) => (
                                            <option key={s.id} value={s.id}>{s.name} ({s.code})</option>
                                        ))}
                                    </select>
                                    {editingItem && <p className="text-xs text-amber-600 mt-1">Mapel tidak dapat diubah saat edit.</p>}
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Jam Per Minggu</label>
                                    <input
                                        type="number"
                                        min="1"
                                        max="10"
                                        value={form.weekly_hours}
                                        onChange={(e) => setForm({ ...form, weekly_hours: Number(e.target.value) })}
                                        className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-emerald-500"
                                        required
                                    />
                                </div>

                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">
                                        Guru Pengampu <span className="text-gray-400 font-normal">(Opsional)</span>
                                    </label>
                                    <select
                                        value={form.teacher_id}
                                        onChange={(e) => setForm({ ...form, teacher_id: e.target.value })}
                                        className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-emerald-500"
                                    >
                                        <option value="">-- Gunakan Guru Default Mapel --</option>
                                        {teachers.map((t) => (
                                            <option key={t.id} value={t.id}>{t.name}</option>
                                        ))}
                                    </select>
                                    <p className="text-xs text-gray-500 mt-1">
                                        Pilih hanya jika guru untuk kelas ini <strong>berbeda</strong> dengan guru default mata pelajaran.
                                    </p>
                                </div>

                                <div className="flex gap-2 mt-4">
                                    {editingItem && (
                                        <button
                                            type="button"
                                            onClick={handleCancelEdit}
                                            className="flex-1 px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors"
                                        >
                                            Batal
                                        </button>
                                    )}
                                    <button
                                        type="submit"
                                        className={`flex-1 flex justify-center items-center gap-2 px-4 py-2 text-white rounded-lg transition-colors ${editingItem ? 'bg-amber-600 hover:bg-amber-700' : 'bg-emerald-600 hover:bg-emerald-700'}`}
                                    >
                                        <Save size={18} />
                                        {editingItem ? 'Update' : 'Simpan'}
                                    </button>
                                </div>
                            </form>
                        </div>
                    </div>

                    {/* Table Section */}
                    <div className="lg:col-span-2">
                        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                            <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                                <h2 className="font-bold text-gray-800">Daftar Mapel Terplot</h2>
                                <span className="px-3 py-1 bg-blue-100 text-blue-800 rounded-full text-sm font-medium">
                                    Total: {totalHours} Jam
                                </span>
                            </div>

                            {loading ? (
                                <div className="p-12 text-center text-gray-400">Loading...</div>
                            ) : classSubjects.length === 0 ? (
                                <div className="p-12 text-center text-gray-400">
                                    Belum ada mata pelajaran dialokasikan untuk kelas ini.
                                </div>
                            ) : (
                                <table className="w-full">
                                    <thead className="bg-gray-50 text-gray-500 text-xs uppercase font-medium">
                                        <tr>
                                            <th className="px-6 py-3 text-left">Mata Pelajaran</th>
                                            <th className="px-6 py-3 text-center">Jam</th>
