                                                            className="p-2 text-amber-500 hover:bg-amber-50 rounded-lg transition-colors"
                                                            title="Edit Alokasi"
                                                        >
                                                            <Pencil size={18} />
                                                        </button>
                                                        <button
                                                            onClick={() => handleDelete(item.id)}
                                                            className="p-2 text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                                                            title="Hapus Alokasi"
                                                        >
                                                            <Trash2 size={18} />
                                                        </button>
                                                    </div>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {!selectedClassId && (
                <div className="text-center py-12 bg-gray-50 rounded-xl border-2 border-dashed border-gray-200">
                    <p className="text-gray-500">Silakan pilih kelas terlebih dahulu untuk melihat dan mengatur kurikulum.</p>
                </div>
            )}
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { getAdminDonations, updateDonation, deleteDonation } from '../../../api';
import { Trash2, CheckCircle, XCircle } from 'lucide-react';
import type { Donation } from '../../../types';
import { useAuth } from '../../../contexts/AuthContext';
import WaliMuridDonations from './WaliMuridDonations';

export default function DonationsIndex() {
  const { user } = useAuth();

  // Show WaliMuridDonations for siswa and wali_murid roles
  if (user?.role === 'siswa' || user?.role === 'wali_murid') {
    return <WaliMuridDonations />;
  }

  // Admin view below
  const [donations, setDonations] = useState<Donation[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [totalDonations, setTotalDonations] = useState(0);

  useEffect(() => {
    fetchDonations();
  }, []);

  const fetchDonations = async () => {
    try {
      const response = await getAdminDonations();
      const data = response.data;
      const donationList = Array.isArray(data) ? data : (data?.data || []);
      setDonations(donationList);

      // Calculate total approved donations
      const total = donationList
        .filter((d: Donation) => d.status === 'approved')
        .reduce((sum: number, d: Donation) => sum + (parseInt(d.amount?.toString() || '0')), 0);
      setTotalDonations(total);
    } catch (error) {
      console.error('Error fetching donations:', error);
      setDonations([]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleUpdateStatus = async (id: number, newStatus: 'approved' | 'rejected') => {
    if (!window.confirm(`Apakah Anda yakin ingin mengubah status menjadi ${newStatus}?`)) return;

    try {
      await updateDonation(id, { status: newStatus });
      fetchDonations(); // Refresh to update totals
    } catch (error) {
      console.error('Error updating donation status:', error);
      alert('Gagal mengubah status donasi');
    }
  };

  const handleDelete = async (id: number) => {
    if (!window.confirm('Apakah Anda yakin ingin menghapus data donasi ini?')) return;

    try {
      await deleteDonation(id);
      setDonations(donations.filter(d => d.id !== id));
    } catch (error) {
      console.error('Error deleting donation:', error);
      alert('Gagal menghapus data donasi');
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-green-main"></div>
      </div>
    );
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <h2 className="font-semibold text-xl text-gray-800 leading-tight">Manajemen Donasi</h2>
      </div>

      <div className="bg-white overflow-hidden shadow-sm sm:rounded-lg">
        <div className="p-6 text-gray-900">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-medium text-gray-900">Daftar Donasi Masuk</h3>
            <Link
              to="/dashboard/donations/settings"
              className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 text-sm font-medium"
            >
              Pengaturan Donasi
            </Link>
          </div>

          {/* Stats Section */}
          <div className="mb-6 grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="bg-green-50 p-4 rounded-lg border border-green-200">
              <div className="text-gray-500 text-sm font-medium uppercase">Total Donasi Terkumpul</div>
              <div className="mt-1 text-2xl font-bold text-green-700">
                Rp {totalDonations.toLocaleString('id-ID')}
              </div>
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Tanggal</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Donatur</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">No. Transaksi</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Nominal</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Aksi</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {donations.length > 0 ? donations.map((donation) => (
                  <tr key={donation.id}>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {new Date(donation.created_at).toLocaleDateString('id-ID')}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      {donation.donor_name}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {donation.transaction_number}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-semibold">
                      Rp {parseInt(donation.amount?.toString() || '0').toLocaleString('id-ID')}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full 
                        ${donation.status === 'approved' ? 'bg-green-100 text-green-800' :
                          donation.status === 'rejected' ? 'bg-red-100 text-red-800' :
                            'bg-yellow-100 text-yellow-800'}`}>
                        {donation.status.charAt(0).toUpperCase() + donation.status.slice(1)}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium space-x-2">
                      {donation.status === 'pending' && (
                        <>
                          <button
                            onClick={() => handleUpdateStatus(donation.id, 'approved')}
                            className="text-green-600 hover:text-green-900 font-semibold"
                          >
                            <CheckCircle className="w-5 h-5" />
                          </button>
                          <button
                            onClick={() => handleUpdateStatus(donation.id, 'rejected')}
                            className="text-red-600 hover:text-red-900 font-semibold ml-2"
                          >
                            <XCircle className="w-5 h-5" />
                          </button>
                        </>
                      )}
                      <button
                        onClick={() => handleDelete(donation.id)}
                        className="text-gray-600 hover:text-gray-900 font-semibold ml-2"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                )) : (
                  <tr>
                    <td colSpan={6} className="px-6 py-4 text-center text-gray-500">
                      Belum ada data donasi.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { getDonationSettings, updateDonationSettings } from '../../../api';
import { toast } from 'react-hot-toast';

interface DonationSettings {
    bank_name: string;
    account_number: string;
    account_holder: string;
    wa_number: string;
}

export default function DonationSettings() {
    const navigate = useNavigate();
    const [formData, setFormData] = useState<DonationSettings>({
        bank_name: '',
        account_number: '',
        account_holder: '',
        wa_number: '',
    });
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        fetchSettings();
    }, []);

    const fetchSettings = async () => {
        try {
            const response = await getDonationSettings();
            if (response.data) {
                setFormData(response.data);
            }
        } catch (error) {
            console.error('Error fetching settings:', error);
            toast.error('Gagal memuat pengaturan donasi');
        } finally {
            setIsLoading(false);
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        try {
            await updateDonationSettings(formData);
            toast.success('Pengaturan donasi berhasil disimpan');
            // Optional: navigate back or stay
        } catch (error) {
            console.error('Error updating settings:', error);
            toast.error('Gagal menyimpan pengaturan');
        } finally {
            setIsSaving(false);
        }
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center py-12">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-green-main"></div>
            </div>
        );
    }

    return (
        <div>
            <div className="flex items-center gap-4 mb-6">
                <Link
                    to="/dashboard/donations"
                    className="p-2 text-gray-500 hover:text-gray-900 bg-white rounded-lg shadow-sm"
                >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                    </svg>
                </Link>
                <h2 className="font-semibold text-xl text-gray-800 leading-tight">Pengaturan Donasi</h2>
            </div>

            <div className="bg-white overflow-hidden shadow-sm sm:rounded-lg max-w-2xl">
                <div className="p-6 text-gray-900">
                    <form onSubmit={handleSubmit} className="space-y-6">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">
                                Nama Bank
                            </label>
                            <input
                                type="text"
                                name="bank_name"
                                value={formData.bank_name}
                                onChange={handleChange}
                                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-brand-green-main focus:border-brand-green-main"
                                placeholder="Contoh: Bank BRI"
                                required
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">
                                Nomor Rekening
                            </label>
                            <input
                                type="text"
                                name="account_number"
                                value={formData.account_number}
                                onChange={handleChange}
                                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-brand-green-main focus:border-brand-green-main"
                                placeholder="Contoh: 1234567890"
                                required
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">
                                Atas Nama
                            </label>
                            <input
                                type="text"
                                name="account_holder"
                                value={formData.account_holder}
                                onChange={handleChange}
                                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-brand-green-main focus:border-brand-green-main"
                                placeholder="Contoh: Panitia Pembangunan"
                                required
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">
                                Nomor WhatsApp Konfirmasi (Opsional)
                            </label>
                            <input
                                type="text"
                                name="wa_number"
                                value={formData.wa_number}
                                onChange={handleChange}
                                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-brand-green-main focus:border-brand-green-main"
                                placeholder="Contoh: 628123456789"
                            />
                            <p className="mt-1 text-xs text-gray-500">Format: 628xxx (tanpa 0 atau +)</p>
                        </div>

                        <div className="flex justify-end pt-4">
                            <button
                                type="submit"
                                disabled={isSaving}
                                className={`px-6 py-2 bg-brand-green-main text-white rounded-lg hover:bg-brand-green-dark font-medium transition-colors ${isSaving ? 'opacity-70 cursor-not-allowed' : ''
                                    }`}
                            >
                                {isSaving ? 'Menyimpan...' : 'Simpan Pengaturan'}
                            </button>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    );
}

import { useCallback, useEffect, useRef, useState } from 'react';
import { Camera, MapPin, Clock, Check, X, AlertCircle, History } from 'lucide-react';
import { getTeacherAttendance, teacherCheckIn, teacherCheckOut } from '../../../api';

interface AttendanceRecord {
    id: number;
    date: string;
    type: 'masuk' | 'keluar';
    status: 'pending' | 'approved' | 'rejected';
    photo: string | null;
    latitude: number | null;
    longitude: number | null;
    location_status: 'valid' | 'invalid';
    admin_note: string | null;
    created_at: string;
}

export default function GuruAbsensi() {
    const [mode, setMode] = useState<'idle' | 'camera'>('idle');
    const [attendanceType, setAttendanceType] = useState<'masuk' | 'keluar'>('masuk');
    const [photo, setPhoto] = useState<string | null>(null);
    const [photoBlob, setPhotoBlob] = useState<Blob | null>(null);
    const [location, setLocation] = useState<{ lat: number; lng: number } | null>(null);
    const [locationError, setLocationError] = useState<string | null>(null);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
    const [history, setHistory] = useState<AttendanceRecord[]>([]);
    const [isLoadingHistory, setIsLoadingHistory] = useState(true);
    const [todayStatus, setTodayStatus] = useState<{ masuk: boolean; keluar: boolean }>({ masuk: false, keluar: false });

    const videoRef = useRef<HTMLVideoElement>(null);
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const streamRef = useRef<MediaStream | null>(null);

    // Time validation (server time should be used, but for UI we show local as hint)
    const now = new Date();
    const currentHour = now.getHours();
    const currentMinute = now.getMinutes();
    const currentTimeStr = `${currentHour.toString().padStart(2, '0')}:${currentMinute.toString().padStart(2, '0')}`;

    const canCheckIn = currentHour >= 7 && currentHour < 8;
    const canCheckOut = currentHour >= 10 && currentHour < 13;

    // Fetch history on mount
    useEffect(() => {
        fetchHistory();
    }, []);

    const fetchHistory = async () => {
        setIsLoadingHistory(true);
        try {
            const response = await getTeacherAttendance({ month: now.getMonth() + 1, year: now.getFullYear() });
            const data = response.data?.data || [];
            setHistory(data);

            // Check today's status
            const today = now.toISOString().split('T')[0];
            const todayRecords = data.filter((r: AttendanceRecord) => r.date === today);
            setTodayStatus({
                masuk: todayRecords.some((r: AttendanceRecord) => r.type === 'masuk'),
                keluar: todayRecords.some((r: AttendanceRecord) => r.type === 'keluar'),
            });
        } catch (error) {
            console.error('Error fetching history:', error);
        } finally {
            setIsLoadingHistory(false);
        }
    };

    // Get current location
    const getLocation = useCallback(() => {
        if (!navigator.geolocation) {
            setLocationError('Geolokasi tidak didukung browser Anda.');
            return;
        }

        navigator.geolocation.getCurrentPosition(
            (position) => {
                setLocation({ lat: position.coords.latitude, lng: position.coords.longitude });
                setLocationError(null);
            },
            (error) => {
                setLocationError(`Gagal mendapatkan lokasi: ${error.message}`);
            },
            { enableHighAccuracy: true, timeout: 10000 }
        );
    }, []);

    // Start camera
    const startCamera = async (type: 'masuk' | 'keluar') => {
        setAttendanceType(type);
        setMode('camera');
        setPhoto(null);
        setPhotoBlob(null);
        setMessage(null);
        getLocation();

        try {
            const stream = await navigator.mediaDevices.getUserMedia({
                video: { facingMode: 'user', width: { ideal: 640 }, height: { ideal: 480 } },
            });
            streamRef.current = stream;
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }
        } catch (error) {
            setMessage({ type: 'error', text: 'Gagal mengakses kamera. Pastikan izin kamera sudah diberikan.' });
            setMode('idle');
        }
    };

    // Stop camera
    const stopCamera = useCallback(() => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach((track) => track.stop());
            streamRef.current = null;
        }
        setMode('idle');
        setPhoto(null);
        setPhotoBlob(null);
    }, []);

    // Capture photo
    const capturePhoto = () => {
        if (!videoRef.current || !canvasRef.current) return;

        const video = videoRef.current;
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        ctx.drawImage(video, 0, 0);

        const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
        setPhoto(dataUrl);

        // Convert to Blob
        canvas.toBlob((blob) => {
            if (blob) setPhotoBlob(blob);
        }, 'image/jpeg', 0.8);

        // Stop video stream after capture
        if (streamRef.current) {
            streamRef.current.getTracks().forEach((track) => track.stop());
        }
    };

    // Submit attendance
    const handleSubmit = async () => {
        if (!photoBlob || !location) {
            setMessage({ type: 'error', text: 'Foto dan lokasi wajib diisi.' });
            return;
        }

        setIsSubmitting(true);
        setMessage(null);

        const formData = new FormData();
        formData.append('photo', photoBlob, 'selfie.jpg');
        formData.append('latitude', location.lat.toString());
        formData.append('longitude', location.lng.toString());

        try {
            const submitFn = attendanceType === 'masuk' ? teacherCheckIn : teacherCheckOut;
            await submitFn(formData);

            setMessage({ type: 'success', text: `Absen ${attendanceType === 'masuk' ? 'Masuk' : 'Keluar'} berhasil dikirim!` });
            stopCamera();
            fetchHistory(); // Refresh history
        } catch (error: unknown) {
            const err = error as { response?: { data?: { message?: string } } };
            setMessage({ type: 'error', text: err.response?.data?.message || 'Gagal mengirim absensi.' });
        } finally {
            setIsSubmitting(false);
        }
    };

    const getStatusBadge = (status: string, locStatus: string) => {
        if (status === 'approved') return 'bg-green-100 text-green-800';
        if (status === 'rejected') return 'bg-red-100 text-red-800';
        if (locStatus === 'invalid') return 'bg-orange-100 text-orange-800';
        return 'bg-yellow-100 text-yellow-800'; // pending
    };

    const getStatusText = (status: string, locStatus: string) => {
        if (status === 'approved') return 'Disetujui';
        if (status === 'rejected') return 'Ditolak';
        if (locStatus === 'invalid') return 'Pending (Lokasi Invalid)';
        return 'Pending';
    };

    return (
        <div className="max-w-2xl mx-auto">
            <h1 className="text-2xl font-bold text-gray-800 mb-6">Absensi Guru</h1>

            {/* Message */}
            {message && (
                <div className={`mb-4 p-4 rounded-lg flex items-center gap-2 ${message.type === 'success' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                    {message.type === 'success' ? <Check size={20} /> : <AlertCircle size={20} />}
                    {message.text}
                </div>
            )}

            {mode === 'idle' && (
                <>
                    {/* Current Time & Status */}
                    <div className="bg-white rounded-xl shadow-sm p-6 mb-6">
                        <div className="flex items-center gap-3 mb-4">
                            <Clock className="text-blue-600" size={24} />
                            <div>
                                <p className="text-sm text-gray-500">Waktu Saat Ini</p>
                                <p className="text-2xl font-bold text-gray-800">{currentTimeStr}</p>
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            {/* Check In Button */}
                            <div>
                                <p className="text-xs text-gray-500 mb-2">Absen Masuk (07:00 - 08:00)</p>
                                <button
                                    onClick={() => startCamera('masuk')}
                                    disabled={!canCheckIn || todayStatus.masuk}
                                    className={`w-full py-3 px-4 rounded-lg font-medium flex items-center justify-center gap-2 transition
                    ${canCheckIn && !todayStatus.masuk
                                            ? 'bg-gradient-to-r from-green-500 to-emerald-600 text-white hover:from-green-600 hover:to-emerald-700'
                                            : 'bg-gray-200 text-gray-500 cursor-not-allowed'
                                        }`}
                                >
                                    <Camera size={20} />
                                    {todayStatus.masuk ? 'Sudah Absen' : 'Absen Masuk'}
                                </button>
                            </div>

                            {/* Check Out Button */}
                            <div>
                                <p className="text-xs text-gray-500 mb-2">Absen Keluar (10:00 - 13:00)</p>
                                <button
                                    onClick={() => startCamera('keluar')}
                                    disabled={!canCheckOut || todayStatus.keluar}
                                    className={`w-full py-3 px-4 rounded-lg font-medium flex items-center justify-center gap-2 transition
                    ${canCheckOut && !todayStatus.keluar
                                            ? 'bg-gradient-to-r from-blue-500 to-indigo-600 text-white hover:from-blue-600 hover:to-indigo-700'
                                            : 'bg-gray-200 text-gray-500 cursor-not-allowed'
                                        }`}
                                >
                                    <Camera size={20} />
                                    {todayStatus.keluar ? 'Sudah Absen' : 'Absen Keluar'}
                                </button>
                            </div>
                        </div>
                    </div>

                    {/* History */}
                    <div className="bg-white rounded-xl shadow-sm p-6">
                        <div className="flex items-center gap-2 mb-4">
                            <History size={20} className="text-gray-600" />
                            <h2 className="text-lg font-semibold text-gray-800">Riwayat Absensi Bulan Ini</h2>
                        </div>

                        {isLoadingHistory ? (
                            <div className="flex justify-center py-8">
                                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
                            </div>
                        ) : history.length === 0 ? (
                            <p className="text-gray-500 text-center py-8">Belum ada data absensi.</p>
                        ) : (
                            <div className="space-y-3 max-h-96 overflow-y-auto">
                                {history.map((record) => (
                                    <div key={record.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                                        <div>
                                            <p className="font-medium text-gray-800">
                                                {new Date(record.date).toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'short' })}
                                            </p>
                                            <p className="text-sm text-gray-500 capitalize">{record.type}</p>
                                        </div>
                                        <span className={`text-xs px-2 py-1 rounded-full ${getStatusBadge(record.status, record.location_status)}`}>
                                            {getStatusText(record.status, record.location_status)}
                                        </span>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </>
            )}

            {mode === 'camera' && (
                <div className="bg-white rounded-xl shadow-sm p-6">
                    <h2 className="text-lg font-semibold text-gray-800 mb-4">
                        Absen {attendanceType === 'masuk' ? 'Masuk' : 'Keluar'}
                    </h2>

                    {/* Camera Preview / Captured Photo */}
                    <div className="relative aspect-[4/3] bg-black rounded-lg overflow-hidden mb-4">
                        {!photo ? (
                            <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
                        ) : (
                            <img src={photo} alt="Captured" className="w-full h-full object-cover" />
                        )}
                    </div>
                    <canvas ref={canvasRef} className="hidden" />

                    {/* Location Status */}
                    <div className="flex items-center gap-2 mb-4 p-3 bg-gray-50 rounded-lg">
                        <MapPin size={20} className={location ? 'text-green-600' : 'text-gray-400'} />
                        {location ? (
                            <span className="text-sm text-green-700">
                                Lokasi: {location.lat.toFixed(6)}, {location.lng.toFixed(6)}
                            </span>
                        ) : locationError ? (
                            <span className="text-sm text-red-600">{locationError}</span>
                        ) : (
                            <span className="text-sm text-gray-500">Mendapatkan lokasi...</span>
                        )}
                    </div>

                    {/* Actions */}
                    <div className="flex gap-3">
                        {!photo ? (
                            <>
                                <button
                                    onClick={stopCamera}
                                    className="flex-1 py-3 px-4 rounded-lg font-medium bg-gray-200 text-gray-700 hover:bg-gray-300 flex items-center justify-center gap-2"
                                >
                                    <X size={20} /> Batal
                                </button>
                                <button
                                    onClick={capturePhoto}
                                    className="flex-1 py-3 px-4 rounded-lg font-medium bg-blue-600 text-white hover:bg-blue-700 flex items-center justify-center gap-2"
                                >
                                    <Camera size={20} /> Ambil Foto
                                </button>
                            </>
                        ) : (
                            <>
                                <button
                                    onClick={() => { setPhoto(null); setPhotoBlob(null); startCamera(attendanceType); }}
                                    className="flex-1 py-3 px-4 rounded-lg font-medium bg-gray-200 text-gray-700 hover:bg-gray-300 flex items-center justify-center gap-2"
                                >
                                    <Camera size={20} /> Ulangi
                                </button>
                                <button
                                    onClick={handleSubmit}
                                    disabled={isSubmitting || !location}
                                    className={`flex-1 py-3 px-4 rounded-lg font-medium flex items-center justify-center gap-2 transition
                    ${isSubmitting || !location
                                            ? 'bg-gray-300 text-gray-500 cursor-not-allowed'
                                            : 'bg-green-600 text-white hover:bg-green-700'
                                        }`}
                                >
                                    {isSubmitting ? (
                                        <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div>
                                    ) : (
                                        <Check size={20} />
                                    )}
                                    Kirim
                                </button>
                            </>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
}

import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getProfileSection, updateProfileSection } from '../../../api';
import MediaSelectInput from '../../../components/MediaSelectInput';

const sectionConfig: Record<string, { title: string; description: string }> = {
  sejarah: {
    title: 'Sejarah',
    description: 'Kelola informasi sejarah madrasah yang akan ditampilkan di halaman profil.',
  },
  proker_kepala: {
    title: 'Program Kerja Kepala',
    description: 'Kelola program kerja kepala madrasah.',
  },
  visi: {
    title: 'Visi & Misi',
    description: 'Kelola visi dan misi madrasah secara terpisah.',
  },
};

interface VisiMisiData {
  visi: { title: string; content: string; image: string };
  misi: { title: string; content: string; image: string };
}

export default function ProfileSectionEdit() {
  const { key } = useParams<{ key: string }>();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [formData, setFormData] = useState({
    title: '',
    content: '',
    image: '',
  });

  // Separate state for Visi & Misi
  const [visiMisiData, setVisiMisiData] = useState<VisiMisiData>({
    visi: { title: 'Visi', content: '', image: '' },
    misi: { title: 'Misi', content: '', image: '' },
  });

  const isVisiMisi = key === 'visi';

  useEffect(() => {
    if (key && sectionConfig[key]) {
      if (isVisiMisi) {
        fetchVisiMisi();
      } else {
        fetchSection();
      }
    } else {
      navigate('/dashboard');
    }
  }, [key]);

  const fetchSection = async () => {
    if (!key) return;
    try {
      setLoading(true);
      const response = await getProfileSection(key);
      const data = response.data;
      setFormData({
        title: data.title || '',
        content: data.content || '',
        image: data.image || '',
      });
    } catch (error) {
      console.error('Error fetching section:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchVisiMisi = async () => {
    try {
      setLoading(true);
      const [visiRes, misiRes] = await Promise.all([
        getProfileSection('visi'),
        getProfileSection('misi'),
      ]);

      setVisiMisiData({
        visi: {
          title: visiRes.data?.title || 'Visi',
          content: visiRes.data?.content || '',
          image: visiRes.data?.image || '',
        },
        misi: {
          title: misiRes.data?.title || 'Misi',
          content: misiRes.data?.content || '',
          image: misiRes.data?.image || '',
        },
      });
    } catch (error) {
      console.error('Error fetching visi misi:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!key) return;

    try {
      setSaving(true);
      await updateProfileSection(key, formData);
      alert('Data berhasil disimpan!');
    } catch (error) {
      console.error('Error saving section:', error);
      alert('Gagal menyimpan data');
    } finally {
      setSaving(false);
    }
  };

  const handleVisiMisiSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      setSaving(true);
      await Promise.all([
        updateProfileSection('visi', visiMisiData.visi),
        updateProfileSection('misi', visiMisiData.misi),
      ]);
      alert('Visi & Misi berhasil disimpan!');
    } catch (error) {
      console.error('Error saving visi misi:', error);
      alert('Gagal menyimpan data');
    } finally {
      setSaving(false);
    }
  };

  const config = key ? sectionConfig[key] : null;

  if (loading) {
    return (
      <div className="flex justify-center items-center min-h-[400px]">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-green-main"></div>
      </div>
    );
  }

  // Special Form for Visi & Misi
  if (isVisiMisi) {
    return (
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold text-gray-900">{config?.title || 'Visi & Misi'}</h1>
            <p className="mt-1 text-sm text-gray-500">{config?.description}</p>
          </div>
        </div>

        {/* Form */}
        <form onSubmit={handleVisiMisiSubmit} className="space-y-6">
          {/* Visi Section */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
            <h2 className="text-lg font-bold text-brand-green-dark mb-4 flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
              </svg>
              VISI
            </h2>

            <div className="space-y-4">
              <div>
                <label htmlFor="visi-title" className="block text-sm font-medium text-gray-700 mb-1">
                  Judul Visi
                </label>
                <input
                  type="text"
                  id="visi-title"
                  value={visiMisiData.visi.title}
                  onChange={(e) => setVisiMisiData({
                    ...visiMisiData,
                    visi: { ...visiMisiData.visi, title: e.target.value }
                  })}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-green-main focus:border-transparent"
                  placeholder="Contoh: VISI"
                />
              </div>

              <div>
                <label htmlFor="visi-content" className="block text-sm font-medium text-gray-700 mb-1">
                  Konten Visi
                </label>
                <textarea
                  id="visi-content"
                  rows={5}
                  value={visiMisiData.visi.content}
                  onChange={(e) => setVisiMisiData({
                    ...visiMisiData,
                    visi: { ...visiMisiData.visi, content: e.target.value }
                  })}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-green-main focus:border-transparent resize-y"
                  placeholder="Tuliskan visi madrasah..."
                  required
                />
              </div>
            </div>
          </div>

          {/* Misi Section */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
            <h2 className="text-lg font-bold text-brand-orange-main mb-4 flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" />
              </svg>
              MISI
            </h2>

            <div className="space-y-4">
              <div>
                <label htmlFor="misi-title" className="block text-sm font-medium text-gray-700 mb-1">
                  Judul Misi
                </label>
                <input
                  type="text"
                  id="misi-title"
                  value={visiMisiData.misi.title}
                  onChange={(e) => setVisiMisiData({
                    ...visiMisiData,
                    misi: { ...visiMisiData.misi, title: e.target.value }
                  })}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-green-main focus:border-transparent"
                  placeholder="Contoh: MISI"
                />
              </div>

              <div>
                <label htmlFor="misi-content" className="block text-sm font-medium text-gray-700 mb-1">
                  Konten Misi
                </label>
                <textarea
                  id="misi-content"
                  rows={8}
                  value={visiMisiData.misi.content}
                  onChange={(e) => setVisiMisiData({
                    ...visiMisiData,
                    misi: { ...visiMisiData.misi, content: e.target.value }
                  })}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-green-main focus:border-transparent resize-y"
                  placeholder="Tuliskan misi madrasah (pisahkan dengan baris baru untuk setiap poin)..."
                  required
                />
                <p className="mt-1 text-xs text-gray-500">
                  Tips: Gunakan baris baru untuk memisahkan setiap poin misi.
                </p>
              </div>
            </div>
          </div>

          {/* Actions */}
          <div className="flex justify-end">
            <button
              type="submit"
              disabled={saving}
              className="px-6 py-2 bg-brand-green-main text-white rounded-lg hover:bg-brand-green-dark disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
              {saving ? 'Menyimpan...' : 'Simpan Visi & Misi'}
            </button>
          </div>
        </form>
      </div>
    );
  }

  // Regular Form for other sections
  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">{config?.title || 'Profil'}</h1>
          <p className="mt-1 text-sm text-gray-500">{config?.description}</p>
        </div>
      </div>

      {/* Form */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200">
        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          {/* Title */}
          <div>
            <label htmlFor="title" className="block text-sm font-medium text-gray-700 mb-1">
              Judul
            </label>
            <input
              type="text"
              id="title"
              value={formData.title}
              onChange={(e) => setFormData({ ...formData, title: e.target.value })}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-green-main focus:border-transparent"
              required
            />
          </div>

          {/* Content */}
          <div>
            <label htmlFor="content" className="block text-sm font-medium text-gray-700 mb-1">
              Konten
            </label>
            <textarea
              id="content"
              rows={10}
              value={formData.content}
              onChange={(e) => setFormData({ ...formData, content: e.target.value })}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-green-main focus:border-transparent resize-y"
              required
            />
            <p className="mt-1 text-xs text-gray-500">
              Anda dapat menggunakan baris baru untuk memisahkan paragraf.
            </p>
          </div>

          {/* Image */}
          <div>
            <MediaSelectInput
              label="Gambar"
              value={formData.image}
              onSelect={(path: string) => setFormData({ ...formData, image: path })}
            />
          </div>

          {/* Actions */}
          <div className="flex justify-end pt-4 border-t border-gray-200">
            <button
              type="submit"
              disabled={saving}
              className="px-6 py-2 bg-brand-green-main text-white rounded-lg hover:bg-brand-green-dark disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
              {saving ? 'Menyimpan...' : 'Simpan Perubahan'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

import { useEffect, useState, useMemo } from 'react';
import { useAuth } from '../../../contexts/AuthContext';
import { getClassSchedules, getPtsSchedules, getPasSchedules, deleteSchedule, getClassRooms, createSchedule, getMySchedules } from '../../../api';
import { Trash2 } from 'lucide-react';
import type { Schedule, ClassRoom } from '../../../types';
import Modal from '../../../components/Modal';
import MediaSelectInput from '../../../components/MediaSelectInput';

export default function ScheduleIndex() {
  const { user } = useAuth();
  const isAdminOrTeacher = user?.role === 'admin' || user?.role === 'guru';

  const [activeTab, setActiveTab] = useState<'class' | 'pts' | 'pas'>('class');
  const [classSchedules, setClassSchedules] = useState<Schedule[]>([]);
  const [ptsSchedules, setPtsSchedules] = useState<Schedule[]>([]);
  const [pasSchedules, setPasSchedules] = useState<Schedule[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Upload State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [classRooms, setClassRooms] = useState<ClassRoom[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [selectedGrade, setSelectedGrade] = useState('');
  const [formData, setFormData] = useState({
    title: '',
    type: 'class',
    grade: '',
    class_room_id: '',
    file_path: '',
    description: ''
  });

  // Fetch logic
  const fetchAllSchedules = async () => {
    setIsLoading(true);
    try {
      if (isAdminOrTeacher) {
        // Admin/Teacher: Fetch all schedules
        const [classRes, ptsRes, pasRes] = await Promise.all([
          getClassSchedules(),
          getPtsSchedules(),
          getPasSchedules(),
        ]);
        setClassSchedules(classRes.data?.schedules || []);
        setPtsSchedules(ptsRes.data?.schedules || []);
        setPasSchedules(pasRes.data?.schedules || []);
      } else {
        // Parent/Student: Fetch my specific schedules
        const response = await getMySchedules();
        const allMySchedules = response.data?.schedules || [];

        // Client-side filtering for tabs since endpoint returns all
        setClassSchedules(allMySchedules.filter((s: Schedule) => s.type === 'class'));
        setPtsSchedules(allMySchedules.filter((s: Schedule) => s.type === 'pts'));
        setPasSchedules(allMySchedules.filter((s: Schedule) => s.type === 'pas'));
      }
    } catch (error) {
      console.error('Error fetching schedules:', error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchAllSchedules();
    fetchClassRooms();
  }, []);

  const fetchClassRooms = async () => {
    try {
      const response = await getClassRooms();
      setClassRooms(Array.isArray(response.data) ? response.data : []);
    } catch (error) {
      console.error('Error fetching class rooms:', error);
    }
  };

  const handleDelete = async (id: number) => {
    if (!window.confirm('Apakah Anda yakin ingin menghapus jadwal ini?')) return;

    try {
      await deleteSchedule(id);
      // Refresh the current tab's data
      if (activeTab === 'class') {
        setClassSchedules(classSchedules.filter(s => s.id !== id));
      } else if (activeTab === 'pts') {
        setPtsSchedules(ptsSchedules.filter(s => s.id !== id));
      } else {
        setPasSchedules(pasSchedules.filter(s => s.id !== id));
      }
    } catch (error) {
      console.error('Error deleting schedule:', error);
      alert('Gagal menghapus jadwal');
    }
  };

  // Filter rombel berdasarkan grade yang dipilih
  const filteredRombels = useMemo(() => {
    if (!selectedGrade) return [];
    return classRooms.filter(cr => String(cr.grade) === selectedGrade);
  }, [selectedGrade, classRooms]);

  const handleOpenModal = () => {
    setSelectedGrade('');
    setFormData({
      title: '',
      type: activeTab,
      grade: '',
      class_room_id: '',
      file_path: '',
      description: ''
    });
    setIsModalOpen(true);
  };

  const handleGradeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newGrade = e.target.value;
    setSelectedGrade(newGrade);
    setFormData(prev => ({ ...prev, grade: newGrade, class_room_id: '' }));
  };

  const handleMediaSelect = (path: string) => {
    setFormData(prev => ({ ...prev, file_path: path }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title || !formData.file_path) {
      alert('Mohon lengkapi judul dan pilih file dari pustaka media');
      return;
    }

    setIsSubmitting(true);
    try {
      const data: Record<string, unknown> = {
        title: formData.title,
        type: formData.type,
        file_path: formData.file_path,
      };

      if (formData.type === 'class') {
        if (formData.grade) data.grade = formData.grade;
        if (formData.class_room_id) data.class_room_id = formData.class_room_id;
      }
      if (formData.description) {
        data.description = formData.description;
      }

      await createSchedule(data);
      alert('Jadwal berhasil ditambahkan');
      setIsModalOpen(false);
      fetchAllSchedules();
    } catch (error) {
      console.error('Error capturing schedule:', error);
      alert('Gagal menambahkan jadwal');
    } finally {
      setIsSubmitting(false);
    }
  };

  const formatDate = (dateString?: string) => {
    if (!dateString) return '-';
    const options: Intl.DateTimeFormatOptions = { day: 'numeric', month: 'short', year: 'numeric' };
    return new Date(dateString).toLocaleDateString('id-ID', options);
  };

  const getTypeName = () => {
    switch (activeTab) {
      case 'class': return 'Jadwal Kelas';
      case 'pts': return 'Jadwal PTS';
      case 'pas': return 'Jadwal PAS';
    }
  };

  const getSchedules = () => {
    switch (activeTab) {
      case 'class': return classSchedules;
      case 'pts': return ptsSchedules;
      case 'pas': return pasSchedules;
    }
  };

  const renderSchedules = (schedules: Schedule[]) => {
    if (schedules.length === 0) {
      return (
        <div className="text-center py-10 bg-gray-50 rounded-lg">
          <p className="text-gray-500">Belum ada {getTypeName()} yang tersedia.</p>
        </div>
      );
    }

    return (
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {schedules.map((schedule) => (
          <div key={schedule.id} className="bg-white border rounded-xl overflow-hidden shadow-sm hover:shadow-md transition">
            <div className="p-4 border-b bg-gray-50 flex justify-between items-center">
              <h3 className="font-bold text-lg text-gray-800">
                {schedule.classRoom?.name || (schedule.grade ? `Kelas ${schedule.grade}` : 'Jadwal')}
              </h3>
              <span className="text-xs text-gray-500">{formatDate(schedule.created_at)}</span>
            </div>

            <div className="p-4">
              <h4 className="font-semibold text-gray-900 mb-2">{schedule.title || 'Tanpa Judul'}</h4>
              {schedule.description && <p className="text-sm text-gray-600 mb-3">{schedule.description}</p>}
              {schedule.file_path && (
                <div className="mb-4">
                  {schedule.file_path.endsWith('.pdf') ? (
                    <a
                      href={schedule.file_path?.startsWith('http') || schedule.file_path?.startsWith('/storage/') ? schedule.file_path : `/storage/${schedule.file_path}`}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="block w-full text-center py-3 bg-blue-50 text-blue-700 rounded-lg font-medium hover:bg-blue-100 transition border border-blue-200"
                    >
                      ­ƒôä Buka Dokumen PDF
                    </a>
                  ) : (
                    <div className="rounded-lg overflow-hidden border border-gray-200">
                      <img
                        src={schedule.file_path?.startsWith('http') || schedule.file_path?.startsWith('/storage/') ? schedule.file_path : `/storage/${schedule.file_path}`}
                        alt="Jadwal"
                        className="w-full h-auto object-cover cursor-pointer"
                        onClick={() => window.open(schedule.file_path?.startsWith('http') || schedule.file_path?.startsWith('/storage/') ? schedule.file_path : `/storage/${schedule.file_path}`, '_blank')}
                      />
                      <div className="text-center text-xs text-gray-500 py-1 bg-gray-50">Klik gambar untuk memperbesar</div>
                    </div>
                  )}
                </div>
              )}
            </div>

            {isAdminOrTeacher && (
              <div className="p-4 border-t flex justify-end">
                <button
                  onClick={() => handleDelete(schedule.id)}
                  className="text-red-500 hover:text-red-700"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            )}
          </div>
        ))}
      </div>
    );
  };

  if (isLoading) {
    // ... loading spinner ...
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-green-main"></div>
      </div>
    );
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold text-gray-800">Jadwal Pelajaran & Ujian</h1>
        {isAdminOrTeacher && (
          <button
            onClick={handleOpenModal}
            className="bg-brand-green-main hover:bg-brand-green-hover text-white px-4 py-2 rounded-lg flex items-center transition"
          >
            <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
            </svg>
            Tambah Jadwal
          </button>
        )}
      </div>

      {/* Tabs */}
      <div className="bg-white rounded-xl shadow-sm mb-6">
        <div className="p-4 flex space-x-4 border-b">
          <button
            className={`py-2 px-4 font-medium transition-colors duration-200 border-b-2 ${activeTab === 'class'
              ? 'border-brand-green-main text-brand-green-main'
              : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            onClick={() => setActiveTab('class')}
          >
            Jadwal Kelas ({classSchedules.length})
          </button>
          <button
            className={`py-2 px-4 font-medium transition-colors duration-200 border-b-2 ${activeTab === 'pts'
              ? 'border-brand-green-main text-brand-green-main'
              : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            onClick={() => setActiveTab('pts')}
          >
            Jadwal PTS ({ptsSchedules.length})
          </button>
          <button
            className={`py-2 px-4 font-medium transition-colors duration-200 border-b-2 ${activeTab === 'pas'
              ? 'border-brand-green-main text-brand-green-main'
              : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            onClick={() => setActiveTab('pas')}
          >
            Jadwal PAS ({pasSchedules.length})
          </button>
        </div>

        <div className="p-6 min-h-[300px]">
          {renderSchedules(getSchedules())}
        </div>
      </div>
      {/* Upload Modal */}
      <Modal
        show={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title="Tambah Jadwal Baru"
      >
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Judul Jadwal</label>
            <input
              type="text"
              value={formData.title}
              onChange={(e) => setFormData({ ...formData, title: e.target.value })}
              className="w-full rounded-lg border-gray-300 focus:border-brand-green-main focus:ring-brand-green-main"
              placeholder="Contoh: Jadwal Kelas 1A Semester Genap"
              required
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Tipe Jadwal</label>
              <select
                value={formData.type}
                onChange={(e) => setFormData({ ...formData, type: e.target.value })}
                className="w-full rounded-lg border-gray-300 focus:border-brand-green-main focus:ring-brand-green-main"
              >
                <option value="class">Jadwal Kelas</option>
                <option value="pts">Jadwal PTS</option>
                <option value="pas">Jadwal PAS</option>
              </select>
            </div>

            {formData.type === 'class' && (
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Kelas</label>
                <select
                  value={selectedGrade}
                  onChange={handleGradeChange}
                  className="w-full rounded-lg border-gray-300 focus:border-brand-green-main focus:ring-brand-green-main"
                  required={formData.type === 'class'}
                >
                  <option value="">Pilih Kelas</option>
                  <option value="1">Kelas 1</option>
                  <option value="2">Kelas 2</option>
                  <option value="3">Kelas 3</option>
                  <option value="4">Kelas 4</option>
                  <option value="5">Kelas 5</option>
                  <option value="6">Kelas 6</option>
                </select>
              </div>
            )}
          </div>

          {/* Rombel dropdown - only show when type is class AND grade is selected */}
          {formData.type === 'class' && selectedGrade && (
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Rombel (Opsional)</label>
              <select
                value={formData.class_room_id}
                onChange={(e) => setFormData({ ...formData, class_room_id: e.target.value })}
                className="w-full rounded-lg border-gray-300 focus:border-brand-green-main focus:ring-brand-green-main"
              >
                <option value="">Semua Rombel (Satu Angkatan)</option>
                {filteredRombels.map((room) => (
                  <option key={room.id} value={room.id}>{room.name}</option>
                ))}
              </select>
              {filteredRombels.length === 0 && (
                <p className="text-xs text-yellow-600 mt-1">Tidak ada rombel untuk kelas ini. Silakan tambahkan rombel terlebih dahulu.</p>
              )}
            </div>
          )}


          <MediaSelectInput
            label="File Jadwal (dari Pustaka Media)"
            value={formData.file_path}
            onSelect={handleMediaSelect}
            id="schedule_file"
          />

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Keterangan (Opsional)</label>
            <textarea
              value={formData.description}
              onChange={(e) => setFormData({ ...formData, description: e.target.value })}
              className="w-full rounded-lg border-gray-300 focus:border-brand-green-main focus:ring-brand-green-main"
              rows={3}
            ></textarea>
          </div>

          <div className="flex justify-end pt-4 space-x-3">
            <button
              type="button"
              onClick={() => setIsModalOpen(false)}
              className="px-4 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 transition"
              disabled={isSubmitting}
            >
              Batal
            </button>
            <button
              type="submit"
              className="px-4 py-2 bg-brand-green-main text-white rounded-lg hover:bg-brand-green-hover transition flex items-center"
              disabled={isSubmitting}
            >
              {isSubmitting ? (
                <>
                  <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Menyimpan...
                </>
              ) : (
                'Simpan Jadwal'
              )}
            </button>
          </div>
        </form>
      </Modal>
    </div>
  );
}

import { useEffect, useState, useMemo } from 'react';
import { getSlotSchedules, getClassRooms, generateSlotSchedules, clearSlotSchedules, getSlotScheduleExportUrl, moveSlotSchedule } from '../../../api';
import { Calendar, Download, RefreshCw, Trash2, AlertCircle } from 'lucide-react';
import type { SlotSchedule, ClassRoom } from '../../../types';
import Modal from '../../../components/Modal';

type Day = 'senin' | 'selasa' | 'rabu' | 'kamis' | 'jumat' | 'sabtu' | 'minggu';

const DAYS: { key: Day; label: string }[] = [
    { key: 'sabtu', label: 'Sabtu' },
    { key: 'minggu', label: 'Ahad' },
    { key: 'senin', label: 'Senin' },
    { key: 'selasa', label: 'Selasa' },
    { key: 'rabu', label: 'Rabu' },
    { key: 'kamis', label: 'Kamis' },
];

const MAX_SLOTS = 7;

const SLOT_TIMES = [
    "07.15 - 07.50", // Jam 1
    "07.50 - 08.25", // Jam 2
    "08.25 - 09.00", // Jam 3
    "09.30 - 10.05", // Jam 4
    "10.05 - 10.40", // Jam 5
    "10.50 - 11.25", // Jam 6
    "11.25 - 12.00", // Jam 7
];

export default function SlotScheduleIndex() {
    const [schedules, setSchedules] = useState<SlotSchedule[]>([]);
    const [classRooms, setClassRooms] = useState<ClassRoom[]>([]);
    const [loading, setLoading] = useState(true);
    const [generating, setGenerating] = useState(false);
    const [selectedClassRoom, setSelectedClassRoom] = useState<number | null>(null);
    const [showGenerateModal, setShowGenerateModal] = useState(false);
    const [selectedClasses, setSelectedClasses] = useState<number[]>([]);
    const [overwrite, setOverwrite] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    // Move/Swap State
    const [selectedSlot, setSelectedSlot] = useState<{ day: Day; slot: number; scheduleId: number } | null>(null);
    const [moving, setMoving] = useState(false);

    useEffect(() => {
        fetchData();
    }, []);

    useEffect(() => {
        if (selectedClassRoom) {
            fetchSchedules();
        }
    }, [selectedClassRoom]);

    const fetchData = async () => {
        try {
            const classRes = await getClassRooms();
            setClassRooms(classRes.data);
            if (classRes.data.length > 0) {
                setSelectedClassRoom(classRes.data[0].id);
            }
        } catch (err) {
            console.error('Error fetching data:', err);
        } finally {
            setLoading(false);
        }
    };

    const fetchSchedules = async () => {
        if (!selectedClassRoom) return;
        try {
            const res = await getSlotSchedules({ class_room_id: selectedClassRoom });
            setSchedules(res.data);
        } catch (err) {
            console.error('Error fetching schedules:', err);
        }
    };

    const scheduleGrid = useMemo(() => {
        const grid: Record<Day, Record<number, SlotSchedule | null>> = {
            senin: {}, selasa: {}, rabu: {}, kamis: {}, jumat: {}, sabtu: {}, minggu: {}
        };
        schedules.forEach(s => {
            if (grid[s.day as Day]) {
                grid[s.day as Day][s.slot_number] = s;
            }
        });
        return grid;
    }, [schedules]);

    const handleGenerate = async () => {
        if (selectedClasses.length === 0) {
            setError('Pilih minimal satu kelas');
            return;
        }

        setGenerating(true);
        setError('');
        setSuccess('');

        try {
            const res = await generateSlotSchedules(selectedClasses, overwrite);
            setSuccess(`Berhasil generate ${res.data.created} jadwal!`);
            setShowGenerateModal(false);
            fetchSchedules();
        } catch (err: unknown) {
            const error = err as { response?: { data?: { error?: string; errors?: string[] } } };
            if (error.response?.data?.errors) {
                setError(error.response.data.errors.join(', '));
            } else if (error.response?.data?.error) {
                setError(error.response.data.error);
            } else {
                setError('Gagal generate jadwal');
            }
        } finally {
            setGenerating(false);
        }
    };

    const handleClear = async () => {
        if (!confirm('Yakin ingin menghapus semua jadwal untuk kelas ini?')) return;
        try {
            await clearSlotSchedules(selectedClassRoom || undefined);
            setSchedules([]);
            setSuccess('Jadwal berhasil dihapus');
        } catch (err) {
            console.error('Error clearing schedules:', err);
        }
    };

    const handleSlotClick = async (day: Day, slot: number, scheduleId?: number) => {
        setError('');
        setSuccess('');

        if (selectedSlot) {
            // If clicking the same slot, deselect
            if (selectedSlot.day === day && selectedSlot.slot === slot) {
                setSelectedSlot(null);
                return;
            }

            // Perform Move/Swap
            if (!selectedClassRoom) return;

            setMoving(true);
            try {
                await moveSlotSchedule({
                    source_id: selectedSlot.scheduleId,
                    target_day: day,
                    target_slot: slot,
                    class_room_id: selectedClassRoom
                });

                setSuccess('Jadwal berhasil dipindahkan/ditukar');
                fetchSchedules();
                setSelectedSlot(null);
            } catch (err: any) {
                setError(err.response?.data?.error || 'Gagal memindahkan jadwal');
            } finally {
                setMoving(false);
            }

        } else {
            // Select Source (only if occupied)
            if (scheduleId) {
                setSelectedSlot({ day, slot, scheduleId });
            }
        }
    };

    const handleExport = (type: 'class' | 'all') => {
        const url = getSlotScheduleExportUrl(type, selectedClassRoom || undefined);
        window.open(url, '_blank');
    };

    const selectedClass = classRooms.find(c => c.id === selectedClassRoom);

    if (loading) {
        return (
            <div className="flex items-center justify-center h-64">
                <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-emerald-500"></div>
            </div>
        );
    }

    return (
        <div className="p-6">
            <div className="flex justify-between items-center mb-6">
                <h1 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
                    <Calendar className="text-emerald-600" />
                    Jadwal Pelajaran (Slot)
                </h1>
                <div className="flex gap-2">
                    <button
                        onClick={() => setShowGenerateModal(true)}
                        className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-colors"
                    >
                        <RefreshCw size={18} />
                        Generate Jadwal
                    </button>
                    <button
                        onClick={() => handleExport('class')}
                        className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                    >
                        <Download size={18} />
                        Export Kelas
                    </button>
                    <button
                        onClick={() => handleExport('all')}
                        className="flex items-center gap-2 px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors"
                    >
                        <Download size={18} />
                        Export Semua
                    </button>
                </div>
            </div>

            {error && (
                <div className="mb-4 p-4 bg-red-100 text-red-700 rounded-lg flex items-center gap-2">
                    <AlertCircle size={20} />
                    {error}
                </div>
            )}

            {success && (
                <div className="mb-4 p-4 bg-green-100 text-green-700 rounded-lg">
                    {success}
                </div>
            )}

            {/* Class Selector */}
            <div className="bg-white rounded-xl shadow-sm p-4 mb-6">
                <div className="flex items-center gap-4">
                    <label className="font-medium text-gray-700">Pilih Kelas:</label>
                    <select
                        value={selectedClassRoom || ''}
                        onChange={(e) => setSelectedClassRoom(Number(e.target.value))}
                        className="px-4 py-2 border rounded-lg focus:ring-2 focus:ring-emerald-500"
                    >
                        {classRooms.map(c => (
                            <option key={c.id} value={c.id}>
                                Kelas {c.grade} {c.name}
                            </option>
                        ))}
                    </select>
                    <button
                        onClick={handleClear}
                        className="ml-auto flex items-center gap-2 px-3 py-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                    >
                        <Trash2 size={18} />
                        Hapus Jadwal Kelas Ini
                    </button>
                </div>
            </div>

            {/* Schedule Grid */}
            <div className={`bg-white rounded-xl shadow-sm overflow-hidden transition-opacity ${moving ? 'opacity-50 pointer-events-none' : ''}`}>
                <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead className="bg-gray-50">
                            <tr>
                                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase w-24">Jam</th>
                                {DAYS.map(day => (
                                    <th key={day.key} className="px-4 py-3 text-center text-xs font-medium text-gray-500 uppercase">
                                        {day.label}
                                    </th>
                                ))}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-200">
                            {Array.from({ length: MAX_SLOTS }, (_, i) => i + 1).map(slot => (
                                <tr key={slot} className="hover:bg-gray-50">
                                    <td className="px-4 py-4 text-sm font-medium text-gray-700 whitespace-nowrap">
                                        <div className="flex flex-col">
                                            <span>Jam {slot}</span>
                                            <span className="text-xs text-gray-400 font-normal">{SLOT_TIMES[slot - 1]}</span>
                                        </div>
                                    </td>
                                    {DAYS.map(day => {
                                        const schedule = scheduleGrid[day.key][slot];
                                        return (
                                            <td
                                                key={day.key}
                                                className={`px-2 py-2 text-center cursor-pointer transition-colors ${selectedSlot?.day === day.key && selectedSlot?.slot === slot
                                                    ? 'bg-blue-100 ring-2 ring-blue-500'
                                                    : selectedSlot
                                                        ? 'hover:bg-blue-50 ring-2 ring-transparent hover:ring-blue-200'
                                                        : ''
                                                    }`}
                                                onClick={() => handleSlotClick(day.key, slot, schedule?.id)}
                                            >
                                                {schedule ? (
                                                    <div className={`rounded-lg p-2 text-xs ${schedule.status === 'pending_swap'
                                                        ? 'bg-yellow-100 border-2 border-yellow-400'
                                                        : 'bg-emerald-50 border border-emerald-200'
                                                        }`}>
                                                        <div className="font-semibold text-gray-800" title={schedule.subject?.name}>
                                                            {schedule.subject?.code}
                                                        </div>
                                                        <div className="text-gray-500 mt-1">
                                                            {schedule.teacher?.name}
                                                        </div>
                                                        {schedule.status === 'pending_swap' && (
                                                            <div className="mt-1 text-yellow-600 text-[10px] font-medium">
                                                                Pending Swap
                                                            </div>
                                                        )}
                                                    </div>
                                                ) : (
                                                    <div className="h-full w-full flex items-center justify-center min-h-[60px] rounded-lg border-2 border-dashed border-gray-100 text-gray-300 text-xs">
                                                        {selectedSlot ? 'Pindah Sini' : '-'}
                                                    </div>
                                                )}
                                            </td>
                                        );
                                    })}
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>

                {schedules.length === 0 && (
                    <div className="text-center py-12 text-gray-500">
                        Belum ada jadwal untuk kelas {selectedClass?.grade} {selectedClass?.name}.
                        <br />
                        Klik "Generate Jadwal" untuk membuat jadwal otomatis.
                    </div>
                )}
            </div>

            {/* Generate Modal */}
            <Modal show={showGenerateModal} onClose={() => setShowGenerateModal(false)}>
                <div className="p-6">
                    <h2 className="text-xl font-bold mb-4">Generate Jadwal Otomatis</h2>

                    {error && (
                        <div className="mb-4 p-3 bg-red-100 text-red-700 rounded-lg text-sm">
                            {error}
                        </div>
                    )}

                    <div className="mb-4">
                        <label className="block text-sm font-medium text-gray-700 mb-2">
                            Pilih Kelas untuk Generate:
                        </label>
                        <div className="max-h-48 overflow-y-auto space-y-2 border rounded-lg p-3">
                            {classRooms.map(c => (
                                <label key={c.id} className="flex items-center gap-2 cursor-pointer hover:bg-gray-50 p-1 rounded">
                                    <input
                                        type="checkbox"
                                        checked={selectedClasses.includes(c.id)}
                                        onChange={(e) => {
                                            if (e.target.checked) {
                                                setSelectedClasses([...selectedClasses, c.id]);
                                            } else {
                                                setSelectedClasses(selectedClasses.filter(id => id !== c.id));
                                            }
                                        }}
                                        className="rounded text-emerald-600 focus:ring-emerald-500"
                                    />
                                    <span>Kelas {c.grade} {c.name}</span>
                                </label>
                            ))}
                        </div>
                        <button
                            onClick={() => setSelectedClasses(classRooms.map(c => c.id))}
                            className="mt-2 text-sm text-emerald-600 hover:underline"
                        >
                            Pilih Semua
                        </button>
                    </div>

                    <div className="mb-4">
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input
                                type="checkbox"
                                checked={overwrite}
                                onChange={(e) => setOverwrite(e.target.checked)}
                                className="rounded text-emerald-600 focus:ring-emerald-500"
                            />
                            <span className="text-sm text-gray-700">
                                Timpa jadwal yang sudah ada
                            </span>
                        </label>
                    </div>

                    <div className="p-3 bg-yellow-50 border border-yellow-200 rounded-lg text-sm text-yellow-800 mb-4">
                        <strong>Catatan:</strong> Pastikan mata pelajaran sudah dikonfigurasi dengan guru pengampu dan jam mingguan per kelas sebelum melakukan generate.
                    </div>

                    <div className="flex justify-end gap-3">
                        <button
                            onClick={() => setShowGenerateModal(false)}
                            className="px-4 py-2 text-gray-700 bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors"
                        >
                            Batal
                        </button>
                        <button
                            onClick={handleGenerate}
                            disabled={generating}
                            className="px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-colors disabled:opacity-50 flex items-center gap-2"
                        >
                            {generating && <RefreshCw size={16} className="animate-spin" />}
                            {generating ? 'Generating...' : 'Generate'}
                        </button>
                    </div>
                </div>
            </Modal>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { getEditStudent, updateStudent, getClassRooms } from '../../../api';
import type { ClassRoom, Student } from '../../../types';
import toast from 'react-hot-toast';
import MediaSelectInput from '../../../components/MediaSelectInput';

export default function EditStudent() {
    const navigate = useNavigate();
    const { id } = useParams<{ id: string }>();
    const [classRooms, setClassRooms] = useState<ClassRoom[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [formData, setFormData] = useState({
        name: '',
        nis: '',
        nisn: '',
        gender: 'L',
        grade: '1',
        class_room_id: '',
        birth_date: '',
        address: '',
        parent_name: '',
        parent_phone: '',
        admission_year: '',
        graduation_year: '',
        status: 'active',
        image: '',
    });

    useEffect(() => {
        fetchClassRooms();
        fetchStudent();
    }, [id]);

    const fetchClassRooms = async () => {
        try {
            const response = await getClassRooms();
            const data = response.data;
            setClassRooms(Array.isArray(data) ? data : (data?.data || []));
        } catch (error) {
            console.error('Error fetching class rooms:', error);
        }
    };

    const fetchStudent = async () => {
        if (!id) return;
        setIsLoading(true);
        try {
            const response = await getEditStudent(Number(id));
            const student: Student = response.data.student || response.data;
            setFormData({
                name: student.name || '',
                nis: student.nis || '',
                nisn: student.nisn || '',
                gender: student.gender || 'L',
                grade: student.grade || '1',
                class_room_id: student.class_room_id?.toString() || '',
                birth_date: student.birth_date || '',
                address: student.address || '',
                parent_name: student.parent_name || '',
                parent_phone: student.parent_phone || '',
                admission_year: student.admission_year || '',
                graduation_year: student.graduation_year || '',
                status: student.status || 'active',
                image: student.image || '',
            });
        } catch (error) {
            console.error('Error fetching student:', error);
            toast.error('Gagal memuat data siswa');
        } finally {
            setIsLoading(false);
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleImageSelect = (path: string) => {
        setFormData(prev => ({ ...prev, image: path }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!id) return;
        setIsSaving(true);

        try {
            const payload = {
                ...formData,
                class_room_id: formData.class_room_id ? Number(formData.class_room_id) : null,
                graduation_year: formData.graduation_year ? Number(formData.graduation_year) : null,
                admission_year: formData.admission_year ? Number(formData.admission_year) : null,
                nis: formData.nis || null,
                nisn: formData.nisn || null,
                parent_name: formData.parent_name || null,
                address: formData.address || null,
                // birth_date and parent_phone are not currently saved by backend but we send them cleanly
                birth_date: formData.birth_date || null,
                parent_phone: formData.parent_phone || null,
                image: formData.image || null,
            };

            await updateStudent(Number(id), payload);
            toast.success('Siswa berhasil diperbarui!');
            navigate('/dashboard/students');
        } catch (error: any) {
            console.error('Error updating student:', error);
            const errorMessage = error.response?.data?.message || error.message || 'Gagal memperbarui siswa';

            // Handle validation errors
            if (error.response?.data?.errors) {
                const validationErrors = Object.values(error.response.data.errors).flat().join('\n');
                toast.error(validationErrors);
            } else {
                toast.error(errorMessage);
            }
        } finally {
            setIsSaving(false);
        }
    };

    const filteredClassRooms = classRooms.filter(cr => String(cr.grade) === formData.grade);

    if (isLoading) {
        return (
            <div className="flex items-center justify-center py-12">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-green-main"></div>
            </div>
        );
    }

    return (
        <div>
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-xl font-bold leading-tight text-gray-800">
                    Edit Data Siswa
                </h2>
            </div>

            <div className="bg-white overflow-hidden shadow-sm sm:rounded-lg">
                <form onSubmit={handleSubmit} className="p-6 space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {/* Nama Lengkap */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Nama Lengkap <span className="text-red-500">*</span>
                            </label>
                            <input
                                type="text"
                                name="name"
                                value={formData.name}
                                onChange={handleChange}
                                required
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                            />
                        </div>

                        {/* NIS */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                NIS <span className="text-red-500">*</span>
                            </label>
                            <input
                                type="text"
                                name="nis"
                                value={formData.nis}
                                onChange={handleChange}
                                required
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                            />
                        </div>

                        {/* NISN */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                NISN
                            </label>
                            <input
                                type="text"
                                name="nisn"
                                value={formData.nisn}
                                onChange={handleChange}
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                            />
                        </div>

                        {/* Jenis Kelamin */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Jenis Kelamin <span className="text-red-500">*</span>
                            </label>
                            <select
                                name="gender"
                                value={formData.gender}
                                onChange={handleChange}
                                required
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                            >
                                <option value="L">Laki-laki</option>
                                <option value="P">Perempuan</option>
                            </select>
                        </div>

                        {/* Status */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Status
                            </label>
                            <select
                                name="status"
                                value={formData.status}
                                onChange={handleChange}
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                            >
                                <option value="active">Aktif</option>
                                <option value="alumni">Alumni</option>
                            </select>
                        </div>

                        {/* Kelas/Grade */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Kelas <span className="text-red-500">*</span>
                            </label>
                            <select
                                name="grade"
                                value={formData.grade}
                                onChange={(e) => {
                                    handleChange(e);
                                    setFormData(prev => ({ ...prev, class_room_id: '' }));
                                }}
                                required
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                            >
                                <option value="1">Kelas 1</option>
                                <option value="2">Kelas 2</option>
                                <option value="3">Kelas 3</option>
                                <option value="4">Kelas 4</option>
                                <option value="5">Kelas 5</option>
                                <option value="6">Kelas 6</option>
                                <option value="Lulus">Lulus (Alumni)</option>
                            </select>
                        </div>

                        {/* Rombel */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Rombel
                            </label>
                            <select
                                name="class_room_id"
                                value={formData.class_room_id}
                                onChange={handleChange}
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                            >
                                <option value="">Pilih Rombel</option>
                                {filteredClassRooms.map(cr => (
                                    <option key={cr.id} value={cr.id}>{cr.name}</option>
                                ))}
                            </select>
                        </div>

                        {/* Tanggal Lahir */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Tanggal Lahir
                            </label>
                            <input
                                type="date"
                                name="birth_date"
                                value={formData.birth_date}
                                onChange={handleChange}
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                            />
                        </div>

                        {/* Tahun Masuk */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Tahun Masuk
                            </label>
                            <input
                                type="text"
                                name="admission_year"
                                value={formData.admission_year}
                                onChange={handleChange}
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                            />
                        </div>

                        {/* Tahun Lulus */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Tahun Lulus
                            </label>
                            <input
                                type="text"
                                name="graduation_year"
                                value={formData.graduation_year}
                                onChange={handleChange}
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                            />
                        </div>

                        {/* Nama Wali */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Nama Wali Murid
                            </label>
                            <input
                                type="text"
                                name="parent_name"
                                value={formData.parent_name}
                                onChange={handleChange}
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                            />
                        </div>

                        {/* No. HP Wali */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                No. HP Wali
                            </label>
                            <input
                                type="text"
                                name="parent_phone"
                                value={formData.parent_phone}
                                onChange={handleChange}
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                            />
                        </div>

                        {/* Alamat */}
                        <div className="md:col-span-2">
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Alamat
                            </label>
                            <textarea
                                name="address"
                                value={formData.address}
                                onChange={handleChange}
                                rows={3}
                                className="w-full border-gray-300 rounded-lg shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                            />
                        </div>

                        {/* Foto Siswa */}
                        <div>
                            <MediaSelectInput
                                label="Foto Siswa"
                                value={formData.image}
                                onSelect={handleImageSelect}
                            />
                        </div>
                    </div>

                    {/* Buttons */}
                    <div className="flex justify-end gap-3 pt-4 border-t">
                        <button
                            type="button"
                            onClick={() => navigate('/dashboard/students')}
                            className="px-4 py-2 text-gray-700 bg-gray-100 rounded-lg hover:bg-gray-200 transition"
                        >
                            Batal
                        </button>
                        <button
                            type="submit"
                            disabled={isSaving}
                            className="px-4 py-2 bg-brand-green-main text-white rounded-lg hover:bg-brand-green-dark transition disabled:opacity-50"
                        >
                            {isSaving ? 'Menyimpan...' : 'Simpan Perubahan'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

import { useEffect, useState, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { Pencil, Trash2 } from 'lucide-react';
import { getAdminStudents, deleteStudent, getClassRooms } from '../../../api';
import type { Student, ClassRoom } from '../../../types';
import { getStorageUrl } from '../../../utils';

export default function StudentsIndex() {
  const [students, setStudents] = useState<Student[]>([]);
  const [classRooms, setClassRooms] = useState<ClassRoom[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [filters, setFilters] = useState({
    grade: '',
    class_room_id: '',
  });

  useEffect(() => {
    fetchClassRooms();
  }, []);

  useEffect(() => {
    fetchStudents();
  }, [filters]);

  const fetchClassRooms = async () => {
    try {
      const response = await getClassRooms();
      // Ensure we access the array correctly. API might return { data: [...] } or { data: { classRooms: [...] } }
      // Based on previous checks, getClassRooms returns response.data which IS the array of classrooms, 
      // OR response.data.classRooms if wrapped.
      // Let's check the API definition in api/index.ts. It returns api.get("/admin/class-rooms").
      // Controller returns response()->json(ClassRoom::all()). So response.data IS the array.
      // However, previous code used response.data.classRooms || []. Let's be safe.
      const data = Array.isArray(response.data) ? response.data : (response.data.classRooms || []);
      setClassRooms(data);
    } catch (error) {
      console.error('Error fetching class rooms:', error);
      setClassRooms([]);
    }
  };

  const fetchStudents = async () => {
    setIsLoading(true);
    try {
      const response = await getAdminStudents({
        grade: filters.grade || undefined,
        class_room_id: filters.class_room_id ? Number(filters.class_room_id) : undefined,
      });

      setStudents(response.data.students || []);
    } catch (error) {
      console.error('Error fetching students:', error);
      setStudents([]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (id: number, name: string) => {
    if (!window.confirm(`Apakah Anda yakin ingin menghapus data siswa "${name}"?`)) return;

    try {
      await deleteStudent(id);
      setStudents(students.filter(s => s.id !== id));
    } catch (error) {
      console.error('Error deleting student:', error);
      alert('Gagal menghapus siswa');
    }
  };

  const handleGradeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setFilters(prev => ({ ...prev, grade: e.target.value, class_room_id: '' }));
  };

  const handleRombelChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setFilters(prev => ({ ...prev, class_room_id: e.target.value }));
  };

  // Filter rombel berdasarkan kelas yang dipilih
  const filteredRombels = useMemo(() => {
    if (!filters.grade) return classRooms;
    return classRooms.filter(cr => String(cr.grade) === filters.grade);
  }, [filters.grade, classRooms]);

  const handlePromote = async () => {
    if (!window.confirm('PERINGATAN: Apakah Anda yakin ingin menaikkan semua siswa ke tingkat berikutnya? \n\n- Kelas 6 akan menjadi Alumni\n- Kelas 5 naik ke 6, dst.\n- Lakukan ini hanya SEKALI pada akhir tahun ajaran!')) return;

    setIsLoading(true);
    try {
      // Assuming promoteStudents is imported from api
      await (await import('../../../api')).promoteStudents();
      alert('Berhasil menaikkan kelas semua siswa!');
      fetchStudents();
    } catch (error) {
      console.error('Error promoting students:', error);
      alert('Gagal melakukan kenaikan kelas.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleDemote = async () => {
    if (!window.confirm('PERINGATAN: Apakah Anda yakin ingin menurunkan semua siswa ke tingkat sebelumnya? \n\n- Alumni tahun ini kembali ke Kelas 6\n- Kelas 2 turun ke 1, dst.\n- Gunakan fitur ini jika terjadi kesalahan saat Naik Kelas Massal.')) return;

    setIsLoading(true);
    try {
      await (await import('../../../api')).demoteStudents();
      alert('Berhasil menurunkan kelas semua siswa!');
      fetchStudents();
    } catch (error) {
      console.error('Error demoting students:', error);
      alert('Gagal melakukan penurunan kelas.');
    } finally {
      setIsLoading(false);
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-green-main"></div>
      </div>
    );
  }

  return (
    <div>
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 gap-4">
        <h2 className="text-xl font-bold leading-tight text-gray-800">
          Manajemen Kesiswaan
        </h2>

        <div className="flex w-full gap-2 md:w-auto">
          {/* Grade Filter */}
          <select
            className="rounded-lg border-gray-300 shadow-sm text-sm focus:border-brand-orange-main focus:ring-brand-orange-main flex-1 md:flex-none md:w-32"
            value={filters.grade}
            onChange={handleGradeChange}
          >
            <option value="">Semua Kelas</option>
            <option value="1">Kelas 1</option>
            <option value="2">Kelas 2</option>
            <option value="3">Kelas 3</option>
            <option value="4">Kelas 4</option>
            <option value="5">Kelas 5</option>
            <option value="6">Kelas 6</option>
            <option value="Lulus">Alumni</option>
          </select>

          {/* Rombel Filter */}
          <select
            className="rounded-lg border-gray-300 shadow-sm text-sm focus:border-brand-orange-main focus:ring-brand-orange-main flex-1 md:flex-none md:w-40"
            value={filters.class_room_id}
            onChange={handleRombelChange}
          >
            <option value="">Semua Rombel</option>
            {filteredRombels.map(cr => (
              <option key={cr.id} value={cr.id}>{cr.name}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Buttons Row (Scrollable on mobile) */}
      <div className="flex gap-2 w-full overflow-x-auto pb-2 hide-scrollbar mb-4">
        <button
          onClick={handlePromote}
          className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded-lg shadow-sm text-sm flex items-center gap-2 whitespace-nowrap"
        >
          Naik Kelas
        </button>

        <button
          onClick={handleDemote}
          className="bg-red-600 hover:bg-red-700 text-white font-bold py-2 px-4 rounded-lg shadow-sm text-sm flex items-center gap-2 whitespace-nowrap"
        >
          Turun Kelas
        </button>

        <Link
          to="/dashboard/classrooms"
          className="bg-purple-600 hover:bg-purple-700 text-white font-bold py-2 px-4 rounded-lg shadow-sm text-sm flex items-center gap-2 whitespace-nowrap"
        >
          Rombel
        </Link>

        <Link
          to="/dashboard/students/create"
          className="bg-brand-orange-main hover:bg-orange-600 text-white font-bold py-2 px-4 rounded-lg shadow-sm text-sm flex items-center gap-2 whitespace-nowrap"
        >
          Data
        </Link>
      </div>

      <div className="bg-white overflow-hidden shadow-sm sm:rounded-lg">
        <div className="p-6 text-gray-900">
          {students.length > 0 ? (
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Nama Lengkap</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">NISN</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Kelamin</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Kelas</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Tahun Masuk</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Tahun Lulus</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Wali Murid</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Alamat</th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Aksi</th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {students.map((student) => (
                    <tr key={student.id}>
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900 flex items-center gap-3">
                        {student.image ? (
                          <img src={getStorageUrl(student.image)} alt={student.name} className="h-8 w-8 rounded-full object-cover" />
                        ) : (
                          <div className="h-8 w-8 rounded-full bg-gray-200 flex items-center justify-center text-xs text-gray-500">
                            {student.name.charAt(0)}
                          </div>
                        )}
                        {student.name}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{student.nisn || student.nis || '-'}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{student.gender === 'L' ? 'Laki-laki' : 'Perempuan'}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                        {student.grade === 'Lulus' ? (
                          <span className="text-blue-600 font-bold">Alumni</span>
                        ) : (student.classRoom || student.class_room) ? (
                          <span>{student.grade} <span className="text-xs text-gray-400">({(student.classRoom || student.class_room)?.name})</span></span>
                        ) : (
                          student.grade || '-'
                        )}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full 
                          ${student.status === 'active' ? 'bg-green-100 text-green-800' :
                            student.status === 'alumni' ? 'bg-blue-100 text-blue-800' : 'bg-red-100 text-red-800'}`}>
                          {student.status?.toUpperCase() || 'ACTIVE'}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{student.admission_year || '-'}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{student.graduation_year || '-'}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{student.parent_name || '-'}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 truncate max-w-xs" title={student.address}>{student.address || '-'}</td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                        <div className="flex items-center gap-2">
                          <Link
                            to={`/dashboard/students/${student.id}/edit`}
                            className="text-indigo-600 hover:text-indigo-900 bg-indigo-50 hover:bg-indigo-100 px-3 py-1 rounded transition-colors"
                          >
                            <Pencil className="w-4 h-4" />
                          </Link>
                          <button
                            onClick={() => handleDelete(student.id, student.name)}
                            className="text-red-600 hover:text-red-900 bg-red-50 hover:bg-red-100 px-3 py-1 rounded transition-colors"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="text-center py-10">
              <div className="text-gray-400 mb-2">Belum ada data kesiswaan.</div>
              <p className="text-sm text-gray-500">Tambahkan data siswa baru untuk memulai.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { getAdminUsers, deleteUser, createUser, updateUser, getUnregisteredTeachers, getUnregisteredStudents } from '../../../api';
import { useAuth } from '../../../contexts/AuthContext';
import { Pencil, Trash2 } from 'lucide-react';
import Modal from '../../../components/Modal';
import type { User } from '../../../types';

interface Teacher {
  id: number;
  name: string;
  nip: string | null;
}

interface Student {
  id: number;
  name: string;
  nis: string | null;
  nisn: string | null;
}

export default function UsersIndex() {
  const { user: currentUser } = useAuth();
  const [users, setUsers] = useState<User[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [role, setRole] = useState('');

  // Modal & Form State
  const [showModal, setShowModal] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);

  // Unregistered data for creating new accounts
  const [unregisteredTeachers, setUnregisteredTeachers] = useState<Teacher[]>([]);
  const [unregisteredStudents, setUnregisteredStudents] = useState<Student[]>([]);
  const [isLoadingOptions, setIsLoadingOptions] = useState(false);

  const initialFormState = {
    name: '',
    email: '',
    password: '',
    role: 'guru',
    identity_number: '',
    person_id: 0, // For new concept: teacher_id or student_id
    student_id: 0, // For wali_murid linking to a student
  };
  const [formData, setFormData] = useState(initialFormState);

  useEffect(() => {
    fetchUsers();
  }, [search, role]);

  const fetchUsers = async () => {
    try {
      const response = await getAdminUsers({ search, role });
      const data = response.data;
      setUsers(Array.isArray(data) ? data : (data?.data || []));
    } catch (error) {
      console.error('Error fetching users:', error);
      setUsers([]);
    } finally {
      setIsLoading(false);
    }
  };

  const fetchUnregisteredData = async () => {
    setIsLoadingOptions(true);
    try {
      const [teachersRes, studentsRes] = await Promise.all([
        getUnregisteredTeachers(),
        getUnregisteredStudents()
      ]);
      setUnregisteredTeachers(teachersRes.data || []);
      setUnregisteredStudents(studentsRes.data || []);
    } catch (error) {
      console.error('Error fetching unregistered data:', error);
    } finally {
      setIsLoadingOptions(false);
    }
  };

  const handleDelete = async (id: number) => {
    if (!window.confirm('Apakah Anda yakin ingin menghapus akun ini?')) return;

    try {
      await deleteUser(id);
      setUsers(users.filter(u => u.id !== id));
    } catch (error) {
      console.error('Error deleting user:', error);
      alert('Gagal menghapus user');
    }
  };

  const handleCreate = async () => {
    setEditingId(null);
    setFormData(initialFormState);
    setShowModal(true);
    await fetchUnregisteredData();
  };

  const handleEdit = (user: User) => {
    setEditingId(user.id);
    setFormData({
      name: user.name,
      email: user.email,
      password: '',
      role: user.role,
      identity_number: user.nip || user.nis || '',
      person_id: 0,
      student_id: user.student_id || 0,
    });
    setShowModal(true);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);

    try {
      if (editingId) {
        // Edit mode - existing behavior
        const payload: Record<string, unknown> = {
          name: formData.name,
          email: formData.email,
          role: formData.role,
        };

        if (formData.password) {
          payload.password = formData.password;
        }

        if (formData.role === 'guru') {
          payload.nip = formData.identity_number;
        } else if (formData.role === 'siswa') {
          payload.nis = formData.identity_number;
        } else {
          payload.nip = formData.identity_number;
        }

        await updateUser(editingId, payload);
      } else {
        // Create mode - NEW behavior
        const payload: Record<string, unknown> = {
          role: formData.role,
          password: formData.password,
        };

        if (formData.role === 'admin') {
          // Admin requires manual input
          payload.name = formData.name;
          payload.email = formData.email;
        } else if (formData.role === 'wali_murid') {
          // Wali murid requires name and student_id
          payload.name = formData.name;
          payload.student_id = formData.student_id;
        } else {
          // Guru/Siswa use person_id from PTK/Kesiswaan
          payload.person_id = formData.person_id;
        }

        await createUser(payload);
      }
      setShowModal(false);
      fetchUsers();
      // Refresh unregistered data after creation
      if (!editingId) {
        fetchUnregisteredData();
      }
    } catch (error) {
      console.error('Error saving user:', error);
      alert('Gagal menyimpan user');
    } finally {
      setIsSaving(false);
    }
  };

  // Get selected person info for display
  const getSelectedPersonInfo = () => {
    if (formData.role === 'guru' && formData.person_id) {
      const teacher = unregisteredTeachers.find(t => t.id === formData.person_id);
      return teacher ? `NIP: ${teacher.nip || '-'}` : '';
    } else if (formData.role === 'siswa' && formData.person_id) {
      const student = unregisteredStudents.find(s => s.id === formData.person_id);
      return student ? `NIS: ${student.nis || '-'} | NISN: ${student.nisn || '-'}` : '';
    }
    return '';
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-green-main"></div>
      </div>
    );
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <h2 className="font-semibold text-xl text-gray-800 leading-tight">Manajemen Akun</h2>
      </div>

      <div className="bg-white overflow-hidden shadow-sm sm:rounded-lg">
        <div className="p-6 text-gray-900">
          <div className="flex flex-col md:flex-row justify-between items-center mb-4 gap-4">
            <div className="flex gap-2">
              <button
                onClick={handleCreate}
                className="bg-purple-600 text-white px-4 py-2 rounded-md hover:bg-purple-700 transition font-medium text-sm"
              >
                + Tambah Akun
              </button>
            </div>

            <div className="flex gap-2 w-full md:w-auto">
              <select
                value={role}
                onChange={(e) => setRole(e.target.value)}
                className="border-gray-300 rounded-md shadow-sm focus:ring-brand-green-main focus:border-brand-green-main text-sm"
              >
                <option value="">Semua Role</option>
                <option value="admin">Admin</option>
                <option value="guru">Guru</option>
                <option value="siswa">Siswa</option>
              </select>

              <input
                type="text"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder="Cari nama, email, nis..."
                className="border-gray-300 rounded-md shadow-sm focus:ring-brand-green-main focus:border-brand-green-main w-full md:w-64 text-sm"
              />
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Nama</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Email/Login</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Password</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Role</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Identitas (NIP/NIS)</th>
                  <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Aksi</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {users.length > 0 ? users.map((user) => (
                  <tr key={user.id}>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm font-medium text-gray-900">{user.name}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm text-gray-500">{user.email}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 font-mono bg-amber-50 px-2 select-all">
                      {user.plain_password || '-'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full 
                        ${user.role === 'admin' ? 'bg-purple-100 text-purple-800' :
                          user.role === 'guru' ? 'bg-blue-100 text-blue-800' :
                            user.role === 'wali_murid' ? 'bg-orange-100 text-orange-800' : 'bg-green-100 text-green-800'}`}>
                        {user.role === 'wali_murid' ? 'Wali Murid' : user.role}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {user.nip || user.nis || '-'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <button
                        onClick={() => handleEdit(user)}
                        className="text-indigo-600 hover:text-indigo-900 mr-4"
                      >
                        <Pencil className="w-4 h-4" />
                      </button>
                      {currentUser?.id !== user.id && (
                        <button
                          onClick={() => handleDelete(user.id)}
                          className="text-red-600 hover:text-red-900"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      )}
                    </td>
                  </tr>
                )) : (
                  <tr>
                    <td colSpan={6} className="px-6 py-4 text-center text-gray-500">
                      Belum ada data user.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* CREATE/EDIT MODAL */}
      <Modal
        show={showModal}
        onClose={() => setShowModal(false)}
        title={editingId ? "Edit Akun Pengguna" : "Tambah Akun Pengguna"}
        maxWidth="xl"
      >
        <form onSubmit={handleSave} className="space-y-4">
          {/* Info Box for Create Mode */}
          {!editingId && (
            <div className="bg-blue-50 border border-blue-200 rounded-md p-3 text-sm text-blue-700">
              <strong>Catatan:</strong> Data guru diambil dari Manajemen PTK, data siswa dari Manajemen Kesiswaan.
              Untuk Wali Murid, masukkan nama wali dan pilih siswa yang terkait.
            </div>
          )}

          {/* Role Selection - Always shown first */}
          <div>
            <label className="block text-sm font-medium text-gray-700">Pilih Role</label>
            <select
              value={formData.role}
              onChange={(e) => setFormData({ ...formData, role: e.target.value, person_id: 0, student_id: 0 })}
              className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
              disabled={!!editingId}
            >
              <option value="guru">Guru</option>
              <option value="siswa">Siswa</option>
              <option value="wali_murid">Wali Murid</option>
              <option value="admin">Admin</option>
            </select>
          </div>

          {/* CREATE MODE: Dynamic Name Selection for Guru/Siswa */}
          {!editingId && (formData.role === 'guru' || formData.role === 'siswa') && (
            <div>
              <label className="block text-sm font-medium text-gray-700">
                Pilih Nama {formData.role === 'guru' ? 'Guru (dari PTK)' : 'Siswa (dari Kesiswaan)'}
              </label>
              {isLoadingOptions ? (
                <div className="mt-1 p-3 bg-gray-50 rounded-md text-sm text-gray-500">
                  Memuat data...
                </div>
              ) : (
                <>
                  <select
                    value={formData.person_id}
                    onChange={(e) => setFormData({ ...formData, person_id: Number(e.target.value) })}
                    className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                    required
                  >
                    <option value={0}>-- Pilih {formData.role === 'guru' ? 'Guru' : 'Siswa'} --</option>
                    {formData.role === 'guru' ? (
                      unregisteredTeachers.length > 0 ? (
                        unregisteredTeachers.map(teacher => (
                          <option key={teacher.id} value={teacher.id}>
                            {teacher.name} {teacher.nip ? `(NIP: ${teacher.nip})` : ''}
                          </option>
                        ))
                      ) : (
                        <option disabled>Tidak ada guru tanpa akun</option>
                      )
                    ) : (
                      unregisteredStudents.length > 0 ? (
                        unregisteredStudents.map(student => (
                          <option key={student.id} value={student.id}>
                            {student.name} {student.nis ? `(NIS: ${student.nis})` : ''}
                          </option>
                        ))
                      ) : (
                        <option disabled>Tidak ada siswa tanpa akun</option>
                      )
                    )}
                  </select>
                  {formData.person_id > 0 && (
                    <p className="mt-1 text-xs text-gray-500">{getSelectedPersonInfo()}</p>
                  )}
                </>
              )}
            </div>
          )}

          {/* CREATE MODE: Wali Murid Input - Name and Student Selection */}
          {!editingId && formData.role === 'wali_murid' && (
            <>
              <div>
                <label className="block text-sm font-medium text-gray-700">Nama Wali Murid</label>
                <input
                  type="text"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                  placeholder="Masukkan nama orang tua/wali"
                  required
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Pilih Siswa yang Dihubungkan</label>
                {isLoadingOptions ? (
                  <div className="mt-1 p-3 bg-gray-50 rounded-md text-sm text-gray-500">
                    Memuat data siswa...
                  </div>
                ) : (
                  <select
                    value={formData.student_id}
                    onChange={(e) => setFormData({ ...formData, student_id: Number(e.target.value) })}
                    className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                    required
                  >
                    <option value={0}>-- Pilih Siswa --</option>
                    {unregisteredStudents.length > 0 ? (
                      unregisteredStudents.map(student => (
                        <option key={student.id} value={student.id}>
                          {student.name} {student.nis ? `(NIS: ${student.nis})` : ''}
                        </option>
                      ))
                    ) : (
                      <option disabled>Tidak ada siswa tersedia</option>
                    )}
                  </select>
                )}
              </div>
            </>
          )}

          {/* CREATE MODE: Admin Manual Input */}
          {!editingId && formData.role === 'admin' && (
            <>
              <div>
                <label className="block text-sm font-medium text-gray-700">Nama Lengkap</label>
                <input
                  type="text"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                  required
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Email</label>
                <input
                  type="email"
                  value={formData.email}
                  onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                  className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                  required
                />
              </div>
            </>
          )}

          {/* EDIT MODE: Full form */}
          {editingId && (
            <>
              <div>
                <label className="block text-sm font-medium text-gray-700">Nama Lengkap</label>
                <input
                  type="text"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700">Email</label>
                <input
                  type="email"
                  value={formData.email}
                  onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                  className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700">
                  {formData.role === 'siswa' ? 'NIS / NISN' : formData.role === 'guru' ? 'NIP' : 'NIP / User ID'}
                </label>
                <input
                  type="text"
                  value={formData.identity_number}
                  onChange={(e) => setFormData({ ...formData, identity_number: e.target.value })}
                  className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
                />
              </div>
            </>
          )}

          {/* Password - Always shown */}
          <div>
            <label className="block text-sm font-medium text-gray-700">
              Password Default {editingId && <span className="text-gray-400 font-normal">(Kosongkan jika tidak ingin mengubah)</span>}
            </label>
            <input
              type="text"
              value={formData.password}
              onChange={(e) => setFormData({ ...formData, password: e.target.value })}
              className="mt-1 block w-full border-gray-300 rounded-md shadow-sm focus:border-brand-green-main focus:ring-brand-green-main"
              placeholder={!editingId ? "Minimal 6 karakter" : ""}
              required={!editingId}
            />
          </div>

          <div className="flex justify-end gap-3 mt-6 pt-4 border-t">
            <button
              type="button"
              onClick={() => setShowModal(false)}
              className="px-4 py-2 border border-gray-300 rounded-md text-sm font-medium text-gray-700 hover:bg-gray-50"
            >
              Batal
            </button>
            <button
              type="submit"
              disabled={isSaving || (!editingId && formData.role !== 'admin' && formData.role !== 'wali_murid' && formData.person_id === 0) || (!editingId && formData.role === 'wali_murid' && (formData.student_id === 0 || !formData.name))}
              className="px-4 py-2 bg-brand-green-main text-white rounded-md text-sm font-medium hover:bg-brand-green-dark disabled:opacity-50"
            >
              {isSaving ? 'Menyimpan...' : 'Simpan'}
            </button>
          </div>
        </form>
      </Modal>
    </div>
  );
}

import { useEffect, useState } from 'react';
import Header from '../../components/Header';
import { getKesiswaan } from '../../api';
import { getStorageUrl } from '../../utils';
import type { Achievement } from '../../types';
import { Link } from 'react-router-dom';
import StudentSection from './StudentList';
import Footer from '../../components/Footer';

export default function Kesiswaan() {
  const [achievements, setAchievements] = useState<Achievement[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'Daftar Murid' | 'Prestasi'>('Daftar Murid');

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await getKesiswaan();
        setAchievements(response.data.achievements || []);
      } catch (error) {
        console.error('Error fetching data:', error);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []);

  const formatDate = (dateString: string) => {
    const options: Intl.DateTimeFormatOptions = { day: 'numeric', month: 'long', year: 'numeric' };
    return new Date(dateString).toLocaleDateString('id-ID', options);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-green-main"></div>
      </div>
    );
  }

  return (
    <>
      <div className="min-h-screen pb-10">
        <Header />

        {/* Navigation Tabs (Profile Style) */}
        {/* Navigation Floating Pills */}
        <div className="w-full max-w-md mx-auto sticky top-2 z-40 px-4 mt-4">
          <div className="bg-white/70 backdrop-blur-xl border border-white/50 rounded-full p-1.5 shadow-lg flex items-center justify-between gap-1 ring-1 ring-black/5">
            {['Daftar Murid', 'Prestasi'].map((tab) => (
              <button
                key={tab}
                onClick={() => setActiveTab(tab as any)}
                className={`flex-1 py-2.5 px-4 rounded-full text-xs font-bold transition-all duration-300 relative overflow-hidden ${activeTab === tab
                  ? 'bg-gradient-to-r from-brand-orange-main to-orange-500 text-white shadow-md transform scale-[1.02]'
                  : 'text-gray-500 hover:text-brand-orange-main hover:bg-white/50'
                  }`}
              >
                {/* Subtle shine effect for active tab */}
                {activeTab === tab && (
                  <span className="absolute inset-0 rounded-full bg-gradient-to-r from-transparent via-white/20 to-transparent animate-shimmer" style={{ backgroundSize: '200% 100%' }}></span>
                )}
                {tab}
              </button>
            ))}
          </div>
        </div>

        <div className="w-full max-w-md mx-auto mt-6 px-4">
          {/* Section Title */}
          <div className="flex items-center gap-2 mb-4">
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-8 h-8 text-brand-orange-main">
              <path fillRule="evenodd" d="M16.28 11.47a.75.75 0 0 1 0 1.06l-7.5 7.5a.75.75 0 0 1-1.06-1.06L14.69 12 7.72 5.03a.75.75 0 0 1 1.06-1.06l7.5 7.5Z" clipRule="evenodd" />
            </svg>
            <h2 className="text-3xl font-bold italic text-brand-orange-main">Kesiswaan</h2>
          </div>

          {/* DAFTAR MURID TAB */}
          {activeTab === 'Daftar Murid' && (
            <StudentSection />
          )}

          {/* PRESTASI TAB */}
          {activeTab === 'Prestasi' && (
            <div className="mb-8 animate-fade-in">
              <h3 className="text-xl font-bold text-brand-green-dark mb-4">Prestasi Siswa</h3>

              {achievements.length === 0 ? (
                <p className="text-gray-500 text-center py-8">Belum ada data prestasi.</p>
              ) : (
                <div className="grid gap-4">
                  {achievements.map((achievement) => (
                    <Link
                      key={achievement.id}
                      to={`/prestasi/${achievement.id}`}
                      className="bg-white rounded-2xl p-4 shadow-md hover:shadow-lg transition-shadow flex gap-4"
                    >
                      <div className="w-20 h-20 bg-gray-200 rounded-xl overflow-hidden shrink-0">
                        {achievement.image ? (
                          <img
                            src={getStorageUrl(achievement.image)}
                            alt={achievement.title}
                            className="w-full h-full object-cover"
                          />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center text-gray-400">
                            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z" />
                            </svg>
                          </div>
                        )}
                      </div>
                      <div className="flex-1">
                        <h4 className="font-bold text-gray-800 mb-1 line-clamp-2">{achievement.title}</h4>
                        {achievement.level && (
                          <span className="text-xs bg-brand-green-main text-white px-2 py-0.5 rounded-full">
                            {achievement.level}
                          </span>
                        )}
                        <p className="text-xs text-gray-400 mt-2">{formatDate(achievement.date)}</p>
                      </div>
                    </Link>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>

        <Footer />
      </div>
    </>
  );
}

import { useEffect, useState } from 'react';
import { getPublicStudents } from '../../api';
import { getStorageUrl } from '../../utils';
import type { Student, ClassRoom } from '../../types';

export default function StudentSection() {
    const [students, setStudents] = useState<Student[]>([]);
    const [classRooms, setClassRooms] = useState<ClassRoom[]>([]);
    const [grades, setGrades] = useState<string[]>([]);

    // Filters
    const [selectedGrade, setSelectedGrade] = useState<string>('');
    const [selectedClassRoom, setSelectedClassRoom] = useState<string>('');

    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const fetchData = async () => {
            setIsLoading(true);
            try {
                const filters: any = {};
                if (selectedGrade) filters.grade = selectedGrade;
                if (selectedClassRoom) filters.class_room_id = parseInt(selectedClassRoom);

                const response = await getPublicStudents(filters);
                setStudents(response.data.students || []);

                // Only set options once to avoid resetting when filtering
                if (grades.length === 0) setGrades(response.data.grades || []);
                if (classRooms.length === 0) setClassRooms(response.data.classRooms || []);

            } catch (error) {
                console.error('Error fetching data:', error);
            } finally {
                setIsLoading(false);
            }
        };

        fetchData();
    }, [selectedGrade, selectedClassRoom]);

    // Filter classrooms based on selected grade
    const filteredClassRooms = selectedGrade
        ? classRooms.filter((c) => c.grade?.toString() === selectedGrade)
        : classRooms;

    return (
        <div className="animate-fade-in">
            {/* Filters */}
            <div className="bg-white p-4 rounded-2xl shadow-sm mb-6 flex gap-2">
                <select
                    value={selectedGrade}
                    onChange={(e) => {
                        setSelectedGrade(e.target.value);
                        setSelectedClassRoom(''); // Reset class when grade changes
                    }}
                    className="flex-1 rounded-xl border-gray-200 text-sm focus:ring-brand-green-main focus:border-brand-green-main"
                >
                    <option value="">Semua Kelas</option>
                    {grades.map((g) => (
                        <option key={g} value={g}>Kelas {g}</option>
                    ))}
                </select>

                <select
                    value={selectedClassRoom}
                    onChange={(e) => setSelectedClassRoom(e.target.value)}
                    className="flex-1 rounded-xl border-gray-200 text-sm focus:ring-brand-green-main focus:border-brand-green-main"
                >
                    <option value="">Semua Rombel</option>
                    {filteredClassRooms.map((c) => (
                        <option key={c.id} value={c.id}>{c.name}</option>
                    ))}
                </select>
            </div>

            {/* Student List */}
            {isLoading ? (
                <div className="flex justify-center py-12">
                    <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-brand-green-main"></div>
                </div>
            ) : students.length === 0 ? (
                <p className="text-gray-500 text-center py-8">Tidak ada data murid.</p>
            ) : (
                <div className="grid grid-cols-2 gap-4">
                    {students.map((student) => (
                        <div key={student.id} className="bg-white rounded-2xl p-3 shadow-md hover:shadow-lg transition-all flex flex-col items-center text-center">
                            <div className="w-20 h-20 rounded-full overflow-hidden bg-gray-100 mb-3 border-2 border-brand-green-light">
                                {student.image ? (
                                    <img
                                        src={getStorageUrl(student.image)}
                                        alt={student.name}
                                        className="w-full h-full object-cover"
                                    />
                                ) : (
                                    <div className="w-full h-full flex items-center justify-center text-gray-300">
                                        <svg className="w-10 h-10" fill="currentColor" viewBox="0 0 24 24">
                                            <path fillRule="evenodd" d="M7.5 6a4.5 4.5 0 1 1 9 0 4.5 4.5 0 0 1-9 0ZM3.751 20.105a8.25 8.25 0 0 1 16.498 0 .75.75 0 0 1-.437.695A18.683 18.683 0 0 1 12 22.5c-2.786 0-5.433-.608-7.812-1.7a.75.75 0 0 1-.437-.695Z" clipRule="evenodd" />
                                        </svg>
                                    </div>
                                )}
                            </div>
                            <h3 className="font-bold text-gray-800 text-sm line-clamp-2 leading-tight mb-1">{student.name}</h3>
                            <p className="text-xs text-brand-green-dark bg-brand-green-light/20 px-2 py-0.5 rounded-full">
                                Kelas {student.grade} {student.class_room?.name}
                            </p>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
}
